(201,'_site_transient_wp_plugin_dependencies_plugin_data','a:2:{s:23:\"frontend-reset-password\";a:35:{s:4:\"name\";s:23:\"Frontend Reset Password\";s:4:\"slug\";s:23:\"frontend-reset-password\";s:7:\"version\";s:5:\"1.3.3\";s:6:\"author\";s:68:\"<a href=\"https://profiles.wordpress.org/wpenhanced/\">Wp Enhanced</a>\";s:14:\"author_profile\";s:42:\"https://profiles.wordpress.org/wpenhanced/\";s:12:\"contributors\";a:2:{s:10:\"wpenhanced\";a:3:{s:7:\"profile\";s:42:\"https://profiles.wordpress.org/wpenhanced/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/2253c528bad1c086a503f8abba77be0bfb076f77408a6d32ec1ea692078c567c?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:11:\"Wp Enhanced\";}s:10:\"rwebster85\";a:3:{s:7:\"profile\";s:42:\"https://profiles.wordpress.org/rwebster85/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/601a29c5cf498a554f9bd819d163fc45e0cab269593143081003da388e7ec637?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:15:\"Richard Webster\";}}s:8:\"requires\";s:3:\"4.4\";s:6:\"tested\";s:5:\"6.9.1\";s:12:\"requires_php\";b:0;s:16:\"requires_plugins\";a:0:{}s:6:\"rating\";i:88;s:7:\"ratings\";a:5:{i:5;i:30;i:4;i:3;i:3;i:0;i:2;i:2;i:1;i:3;}s:11:\"num_ratings\";i:38;s:11:\"support_url\";s:61:\"https://wordpress.org/support/plugin/frontend-reset-password/\";s:15:\"support_threads\";i:4;s:24:\"support_threads_resolved\";i:3;s:15:\"active_installs\";i:10000;s:12:\"last_updated\";s:22:\"2026-01-30 10:23am GMT\";s:5:\"added\";s:10:\"2018-01-13\";s:8:\"homepage\";s:0:\"\";s:8:\"sections\";a:6:{s:11:\"description\";s:3202:\"<p><strong>Frontend Reset Password</strong> lets your site users reset their lost or forgotten passwords in the frontend of your site. No more default WordPress reset form! Users fill in their username or email address and a reset password link is emailed to them. When they click this link they&#8217;ll be redirected to your site and asked for a new password. Everything is handled using default WordPress methods including security, so you don&#8217;t have to worry.</p>\n<p><strong>Frontend Reset Password</strong> is perfect for sites that have disabled access to the WordPress dashboard, or if you want to include a lost/reset password form on one of your custom site pages. It also works great with <strong>Easy Digital Downloads</strong>!</p>\n<p>Any error messages display right on the form, including whether the username or email address is invalid.</p>\n<p>The plugin works by hooking into the <code>lostpassword_url</code> WordPress filter, meaning compatibility with other plugins can be better maintained.</p>\n<p><strong>Frontend Reset Password</strong> is also translation ready.</p>\n<p><strong>New:</strong><br />\n&#8211; Modern settings framework for easy configuration &amp; searching our documentation<br />\n&#8211; Password requirements and eye icon toggle<br />\n&#8211; Customizable reset link text and email templates<br />\n&#8211; Full documentation at https://docs.wpenhanced.com/frontend-reset-password/</p>\n<h3>Documentation</h3>\n<p>Full documentation and setup guide:<br />\nhttps://docs.wpenhanced.com/frontend-reset-password/</p>\n<p>Find answers, usage examples, and troubleshooting tips on our official documentation site.</p>\n<h3>Setup Guide</h3>\n<p>Quick Start:<br />\n1. Add the shortcode <code>[reset_password]</code> to any page.<br />\n2. Visit <strong>Settings &gt; Frontend Reset Password</strong> in your WordPress admin to select your reset page and configure options.<br />\n3. (Optional) Customize form text, password requirements, and email templates.</p>\n<p>See the <a href=\"https://docs.wpenhanced.com/frontend-reset-password/\" rel=\"nofollow ugc\">online documentation</a> for screenshots and advanced usage.</p>\n<h3>Customisation</h3>\n<p><strong>Customisation Features:</strong><br />\n&#8211; Change all form text and labels<br />\n&#8211; Set password requirements (length, character types)<br />\n&#8211; Show/hide eye icon for password fields<br />\n&#8211; Customize email subject, sender, and template<br />\n&#8211; Display login link after password reset</p>\n<p>Very little CSS styling is used, so the forms should style with your website theme beautifully.</p>\n<p>If you use a frontend login page you can set that in the plugin also. Users are told they can login and are shown the url when they successfully change their password.</p>\n<p>You can also set the minimum number of characters required for a password. Default is 0.</p>\n<h3>Support &amp; Resources</h3>\n<ul>\n<li><a href=\"https://docs.wpenhanced.com/frontend-reset-password/\" rel=\"nofollow ugc\">Full Documentation</a></li>\n<li>Quick start guide in plugin settings</li>\n<li><a href=\"https://wordpress.org/support/plugin/frontend-reset-password/\" rel=\"ugc\">WordPress.org Support Forum</a></li>\n</ul>\n\";s:12:\"installation\";s:1171:\"<p><strong>Manually in WordPress</strong></p>\n<ol>\n<li>Download the plugin ZIP file from WordPress.org</li>\n<li>From the WordPress admin dashboard go to Plugins, Add New</li>\n<li>Click Upload Plugin, locate the file, upload</li>\n<li>In the WordPress dashboard go to Plugins, Installed Plugins, and activate <strong>Frontend Reset Password</strong></li>\n<li>Make sure to read the quick start guide! (it&#8217;s really short)</li>\n</ol>\n<p><strong>Manually using FTP</strong></p>\n<ol>\n<li>Download the plugin ZIP file, extract it</li>\n<li>FTP to your server and go to your root WordPress directory</li>\n<li>Navigate to wp-content/plugins</li>\n<li>Upload the parent directory <em>som-frontend-reset-password</em> &#8211; the folder that contains the file som-frontend-reset-password.php &#8211; to that location</li>\n<li>In the WordPress dashboard go to Plugins, Installed Plugins, and activate <strong>Frontend Reset Password</strong></li>\n<li>Make sure to read the quick start guide! (it&#8217;s really short)</li>\n</ol>\n<p>For detailed installation steps, troubleshooting, and advanced configuration, visit:<br />\nhttps://docs.wpenhanced.com/frontend-reset-password/</p>\n\";s:3:\"faq\";s:1065:\"<p><strong>The e-mail could not be sent:</strong> This happens when the wp_mail() function call fails. If you&#8217;re testing the plugin on a localhost and don&#8217;t use a local email server, this error will show.</p>\n<p><strong>Settings page dropdown shows 403 or &#8220;Failed to load resource&#8221; (Solid Security):</strong> If you use Solid Security (formerly iThemes Security) with &#8220;Restrict REST API&#8221; enabled, the page selector in settings can be blocked. This plugin automatically allows logged-in administrators to load the pages list for that dropdown only. Make sure you are logged in as an admin when opening the settings page. If the dropdown still fails, temporarily set Solid Security&#8217;s REST API access to &#8220;Default&#8221; under Security &gt; Settings &gt; Advanced, or check that your user has the &#8220;manage_options&#8221; capability.</p>\n<p>See the <a href=\"https://docs.wpenhanced.com/frontend-reset-password/#faq\" rel=\"nofollow ugc\">FAQ section in our documentation</a> for more common questions and solutions.</p>\n\";s:9:\"changelog\";s:7215:\"<h4>1.3.3</h4>\n<p>30th January 2026 =<br />\n* [MOD] Strange, endless update loop (saying it was still 1.3.1)</p>\n<h4>1.3.2</h4>\n<p>30th January 2026 =<br />\n* [MOD] Page dropdown in settings now uses AJAX only (one request shared across all page fields); works when REST API is restricted</p>\n<h4>1.3.1</h4>\n<p>29th January 2026 =<br />\n* [FIX] Password reset form no longer shows raw special characters or regex in the page when special character requirement is enabled<br />\n* [FIX] Settings page &#8220;page dropdown&#8221; now works when Solid Security (or similar) blocks the public REST API</p>\n<h4>1.3.0 &#8211; 28th January 2026</h4>\n<ul>\n<li>[NEW] New settings framework for our common brand. Search documentation and settings in WordPress admin</li>\n<li>[NEW] Full documentation site: https://docs.wpenhanced.com/frontend-reset-password/</li>\n<li>[NEW] Customizable special characters for password requirements. Now uses the full OWASP recommended character set by default, and allows admins to customize the allowed characters.</li>\n<li>[NEW] Added Settings link on the Plugins page for quick access to plugin settings</li>\n<li>[MOD] Removal of google font being loaded in CSS</li>\n<li>[MOD] Legacy Settings menu (Settings &gt; Frontend Reset Password) now redirects to the new WP Enhanced settings page</li>\n</ul>\n<h4>1.2.5 &#8211; 23rd January 2026</h4>\n<ul>\n<li>[MOD] Confirmed compatibility with WordPress 6.9</li>\n</ul>\n<h4>1.2.4 &#8211; 20th August 2025</h4>\n<ul>\n<li>[NEW] New setting &#8220;Reset Link Text&#8221; &#8211; this will change the reset link text in the email from the URL to be what you add in the setting.</li>\n<li>[NEW] New Setting &#8220;Show Eye Icon on Password Fields&#8221; &#8211; if enabled it will allow the users to toggle the password visibility on the reset password.*</li>\n<li>[NEW] Added optional password format requirements. You can now choose to require at least one lowercase letter, one uppercase letter, one number, and/or one special character. Each requirement can be enabled individually.*</li>\n<li>[MOD] Modified the password reset form to display the requirements (character length and format requirements) in a list form and if they do not meet them, it will be red. When they meet the requirement it will go green.</li>\n<li>[THANKS] Special thanks to Colin Stearman (@britcoder) for his contributions and suggestions toward these enhancements.</li>\n</ul>\n<h4>1.2.3 &#8211; 16th April 2025</h4>\n<ul>\n<li>Fixed bug when using WP 2FA</li>\n<li>Added {email} tag as option for custom email template</li>\n<li>Fix fatal error when there are issues sending email</li>\n<li>Fixed issue where translations were not loading from frontend-reset-password-LANG.mo</li>\n</ul>\n<h4>1.2.2 &#8211; 1st August 2023</h4>\n<ul>\n<li>MOD: Lost Password Form &#8211; Accessibility</li>\n</ul>\n<h4>1.2.1 &#8211; 8th November 2022</h4>\n<ul>\n<li>MOD: Updated branding to match WP Enhanced</li>\n<li>MOD: Updated &#8220;tested up to&#8221; so its not out of date anymore</li>\n</ul>\n<h4>1.2 &#8211; 13th July 2020</h4>\n<ul>\n<li>[New Feature] Setting to change the email subject.</li>\n<li>[Change] Additional <code>esc_html()</code> calls added to frontend facing text.</li>\n<li>[Change] All translatable strings using <code>__</code> have been converted to <code>esc_html__()</code>.</li>\n<li>[Change] Updated POT file included.</li>\n</ul>\n<h4>1.1.91</h4>\n<ul>\n<li>New Feature: Custom templates. Template files can now be included in your child theme folder. Create a new folder inside your child theme directory called <code>somfrp-templates</code>, and follow the same template folder/file structure as found in the plugin&#8217;s <code>templates</code> folder.</li>\n<li>Change: Now uses <code>add_query_arg()</code> when creating a reset password link, to improve compatibility</li>\n<li>Change: Username no longer included in reset password link, switched to using user ID</li>\n<li>Change: Changes made to <code>lost_password_form.php</code> template file</li>\n<li>Change: Tested up to WordPress 5.4</li>\n</ul>\n<h4>1.1.9</h4>\n<ul>\n<li>Fix: Changed the way error messages are displayed to improve security. As such the plugin template files have changed, meaning any custom ones you have made will need to be updated to reflect the new changes.</li>\n<li>Change: Removed redundant <code>&lt;i&gt;</code> element from <code>lost_password_form.php</code>.</li>\n</ul>\n<h4>1.1.8</h4>\n<ul>\n<li>New Feature: Custom templates. You can now override the form templates in your theme. Create a new folder inside your theme directory called <code>somfrp-templates</code>, and follow the same template folder/file structure as found in the plugin&#8217;s <code>templates</code> folder.</li>\n</ul>\n<h4>1.1.7</h4>\n<ul>\n<li>Change: More HTML tags are now available to use in email messages, since the saved message is now included in the email raw, but still uses the <code>wpautop()</code> function to automatically add <code>&lt;p&gt;</code> tags</li>\n</ul>\n<h4>1.1.6</h4>\n<ul>\n<li>Change: Replaced filter &#8216;retrieve_password_title&#8217; with &#8216;somfrp_retrieve_password_title&#8217; to prevent other plugins unintentionally overriding the email title</li>\n<li>Change: Replaced filter &#8216;retrieve_password_message&#8217; with &#8216;somfrp_retrieve_password_message&#8217; to prevent other plugins unintentionally overriding the email message</li>\n<li>Change: Set priority for lostpassword_url filter to 999</li>\n<li>Change: Moved plugin settings page from the Plugins section to the Settings section of the admin menu</li>\n</ul>\n<h4>1.1.5</h4>\n<ul>\n<li>Change: Removed login check to allow resetting password when logged in</li>\n<li>Fix: Error output corrected for the invalid_key index</li>\n</ul>\n<h4>1.1.41</h4>\n<ul>\n<li>Fix: Corrected bug with action displaying form</li>\n</ul>\n<h4>1.1.4</h4>\n<ul>\n<li>Change: Changed to using &#8220;somfrp_action&#8221; parameter rather than &#8220;action&#8221; to avoid conflicts</li>\n</ul>\n<h4>1.1.3</h4>\n<ul>\n<li>Change: Functions to override default lost password actions and filters have a higher priority number</li>\n</ul>\n<h4>1.1.2</h4>\n<ul>\n<li>Change: Email sent confirmation text no longer shows the email address</li>\n</ul>\n<h4>1.1.1</h4>\n<ul>\n<li>Fix: Custom text for the reset form now outputs HTML tags correctly</li>\n</ul>\n<h4>1.1</h4>\n<ul>\n<li>New feature: Customise the name and email address that the reset password emails send from, rather than the default wordpress@yoursite.com</li>\n<li>New feature: Plugin now sends HTML formatted emails which can be fully customised in the settings</li>\n<li>New feature: Select custom pages to redirect to for the email sent successfully and password changed pages, rather than the reset password page handling everything</li>\n</ul>\n<h4>1.0.5</h4>\n<ul>\n<li>Cleaned undefined index errors</li>\n<li>Change wp_mail() headers to better support some plugins/themes</li>\n</ul>\n<h4>1.0.4</h4>\n<ul>\n<li>Fixed missing WP_Error object on password validation</li>\n</ul>\n<h4>1.0.3</h4>\n<ul>\n<li>Plugin now translation ready</li>\n</ul>\n<h4>1.0.2</h4>\n<ul>\n<li>Textdomain set for language file</li>\n</ul>\n<h4>1.0.1</h4>\n<ul>\n<li>Textdomain fix</li>\n</ul>\n<h4>1.0</h4>\n<ul>\n<li>Initial release</li>\n</ul>\n\";s:11:\"screenshots\";s:597:\"<ol><li><a href=\"https://ps.w.org/frontend-reset-password/assets/screenshot-1.png?rev=3445607\"><img src=\"https://ps.w.org/frontend-reset-password/assets/screenshot-1.png?rev=3445607\" alt=\"Reset Password Form (Twenty Seventeen Theme)\"></a><p>Reset Password Form (Twenty Seventeen Theme)</p></li><li><a href=\"https://ps.w.org/frontend-reset-password/assets/screenshot-2.png?rev=3445607\"><img src=\"https://ps.w.org/frontend-reset-password/assets/screenshot-2.png?rev=3445607\" alt=\"Enter New Password Form (Twenty Seventeen Theme)\"></a><p>Enter New Password Form (Twenty Seventeen Theme)</p></li></ol>\";s:7:\"reviews\";s:15876:\"<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Superb Little Plugin</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/alistairgd/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/f5190914fcc1f61889cbc1b6954e950070c7db83fe90e547e85f584d2f31f787?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/f5190914fcc1f61889cbc1b6954e950070c7db83fe90e547e85f584d2f31f787?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/alistairgd/\" class=\"reviewer-name\">alistairgd</a> op <span class=\"review-date\">december 17, 2024</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Great little plugin that allows easy front end password resets for users while keeping them out of their backend profile page.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Your plugin is a pure marvel</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/david38220/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/3c1118f93830ee5ce1561a1926d1b8393b0d3a8ade3d231b7212be241f6feed4?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/3c1118f93830ee5ce1561a1926d1b8393b0d3a8ade3d231b7212be241f6feed4?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/david38220/\" class=\"reviewer-name\">david38220</a> op <span class=\"review-date\">november 17, 2024</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Great, a big thank you, your plugin is easy to use, fully customizable, works wonderfully well and without bugs</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Super easy and usefull!</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/gokhaanc/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/a4bfb9b27559f5b90cecee85a46d14438b429351cf49c6de9286e9b909492f13?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/a4bfb9b27559f5b90cecee85a46d14438b429351cf49c6de9286e9b909492f13?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/gokhaanc/\" class=\"reviewer-name\">gokhaanc</a> op <span class=\"review-date\">augustus 16, 2024</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>It\'s super easy to use, works well and does not come bloated with extra nonsense just does its job. I use it to override Learnpress login page. Thank you!</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Great Plugin for my leardash website, Thanks :)</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/alexkarc/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/709487d1995b89c935b34a0b4f13caad3afeb3ba0395ee882dc2f8b82348c702?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/709487d1995b89c935b34a0b4f13caad3afeb3ba0395ee882dc2f8b82348c702?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/alexkarc/\" class=\"reviewer-name\">alexkarc</a> op <span class=\"review-date\">juni 30, 2023</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>This Plugin has a lot of functions, even customizing password reset email, very nice !!!!</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Great Plugin - Easy to handle</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/filewalker/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/543e16fa6258f71b681a643ed864d9e849c0713c48712784c22cbb7dc1c218a5?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/543e16fa6258f71b681a643ed864d9e849c0713c48712784c22cbb7dc1c218a5?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/filewalker/\" class=\"reviewer-name\">filewalker</a> op <span class=\"review-date\">juli 7, 2021</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\">Thanks, this is one of the easy to install and use plugins I ever saw.\nThere is just one little tiny thing. The in the frontend used words:\n- Email Address or Username\n  templates/lost_password_form.php:46\n- New Password\n  templates/lost_password_reset_form.php:42\n- Re-enter Password\n  templates/lost_password_reset_form.php:55\n- Sorry, that key has expired. Please reset your password again.\n  includes/somfrp-functions.php:536\n- Sorry, that key does not appear to be valid. Please reset your password again.\n  includes/somfrp-functions.php:540\n\nAre not translateable in the plugin config form. You have to go into the code. \n\nAnyway thanks a lot for the plugin!</div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Excelente plugin</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/diza/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/812c2573f9b2b5aa9e8a33c0b5847a040b01a906252301973b0ab8ad85e35151?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/812c2573f9b2b5aa9e8a33c0b5847a040b01a906252301973b0ab8ad85e35151?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/diza/\" class=\"reviewer-name\">diza</a> op <span class=\"review-date\">februari 27, 2021</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\">Excelente, fácil de usar y tiene grandes características para ser totalmente gratuito.</div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Ty for recognizing the problem</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/zachkinsey/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/4bc19dde3fe13321161cca30bd09c4a2a9c4b77468980e2b26a889ff53a79cc0?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/4bc19dde3fe13321161cca30bd09c4a2a9c4b77468980e2b26a889ff53a79cc0?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/zachkinsey/\" class=\"reviewer-name\">zachkinsey</a> op <span class=\"review-date\">februari 1, 2021</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\">I use elementor to help build out my registration/login flow, but creating a custom forgot password form without an elementor add-on or developer level knowledge is impossible <em>(as far as I know)</em>.... that is, until now.\n\nThanks to this plugin, I don\'t have to purchase an extra plugin or hire a developer.\n\nBefore this plugin, I was considering using an elementor form + my CRM to handle passwords... but, I soon realized that was a bad idea...\n\nAfter all, who wants passwords to User accounts chilling in plain text etc. etc.?\n\nNot I.\n\nThanks guys.</div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Works perfect!</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/alinaalinuta/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/51e4d55fd888ab55cfe627d6f22de01819a5a95a368145b63f339f98c76a0d70?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/51e4d55fd888ab55cfe627d6f22de01819a5a95a368145b63f339f98c76a0d70?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/alinaalinuta/\" class=\"reviewer-name\">alinaalinuta</a> op <span class=\"review-date\">januari 20, 2021</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\">It is easy to use and works perfect. I would like this plugin could have more customization... but I am very grateful it exist :)</div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">It does the job right</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/danielepais/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/69b74a8b449201f3e9e4c562803d8ede0bb97bd5ad04af631f12d6a7cac673ea?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/69b74a8b449201f3e9e4c562803d8ede0bb97bd5ad04af631f12d6a7cac673ea?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/danielepais/\" class=\"reviewer-name\">danielepais</a> op <span class=\"review-date\">januari 18, 2021</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\">Exactly what I needed, a no fuss front page reset password system that works.</div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Unfortunately doesn&#039;t work</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/deeholzman/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/3313e8cc679eda3e95a1ed9713fbd12d37ec60b8e6396567bf86d11757f3256c?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/3313e8cc679eda3e95a1ed9713fbd12d37ec60b8e6396567bf86d11757f3256c?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/deeholzman/\" class=\"reviewer-name\">deeholzman</a> op <span class=\"review-date\">januari 8, 2021</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\">Great idea for a plugin, but the reset password email is never sent, and when a user tries to enter their username or email to reset the password, it fails silently and redirects to the default Wordpress login page, even when a custom login page is specified.</div>\n</div>\n\";}s:17:\"short_description\";s:81:\"Let your users reset their forgotten passwords from the frontend of your website.\";s:13:\"download_link\";s:66:\"https://downloads.wordpress.org/plugin/frontend-reset-password.zip\";s:14:\"upgrade_notice\";a:0:{}s:11:\"screenshots\";a:2:{i:1;a:2:{s:3:\"src\";s:76:\"https://ps.w.org/frontend-reset-password/assets/screenshot-1.png?rev=3445607\";s:7:\"caption\";s:44:\"Reset Password Form (Twenty Seventeen Theme)\";}i:2;a:2:{s:3:\"src\";s:76:\"https://ps.w.org/frontend-reset-password/assets/screenshot-2.png?rev=3445607\";s:7:\"caption\";s:48:\"Enter New Password Form (Twenty Seventeen Theme)\";}}s:4:\"tags\";a:4:{s:5:\"login\";s:5:\"login\";s:13:\"lost-password\";s:13:\"lost password\";s:8:\"password\";s:8:\"password\";s:14:\"reset-password\";s:14:\"reset password\";}s:8:\"versions\";a:6:{s:5:\"1.2.4\";s:72:\"https://downloads.wordpress.org/plugin/frontend-reset-password.1.2.4.zip\";s:5:\"1.2.5\";s:72:\"https://downloads.wordpress.org/plugin/frontend-reset-password.1.2.5.zip\";s:5:\"1.3.0\";s:72:\"https://downloads.wordpress.org/plugin/frontend-reset-password.1.3.0.zip\";s:5:\"1.3.1\";s:72:\"https://downloads.wordpress.org/plugin/frontend-reset-password.1.3.1.zip\";s:5:\"1.3.2\";s:72:\"https://downloads.wordpress.org/plugin/frontend-reset-password.1.3.2.zip\";s:5:\"1.3.3\";s:72:\"https://downloads.wordpress.org/plugin/frontend-reset-password.1.3.3.zip\";}s:14:\"business_model\";b:0;s:14:\"repository_url\";s:0:\"\";s:22:\"commercial_support_url\";s:0:\"\";s:11:\"donate_link\";s:82:\"https://www.paypal.com/cgi-bin/webscr?cmd=_s-xclick&hosted_button_id=VAYF6G99MCMHU\";s:7:\"banners\";a:2:{s:3:\"low\";s:78:\"https://ps.w.org/frontend-reset-password/assets/banner-772x250.png?rev=3445607\";s:4:\"high\";s:79:\"https://ps.w.org/frontend-reset-password/assets/banner-1544x500.png?rev=3445607\";}s:5:\"icons\";a:2:{s:2:\"1x\";s:76:\"https://ps.w.org/frontend-reset-password/assets/icon-128x128.png?rev=3445607\";s:2:\"2x\";s:76:\"https://ps.w.org/frontend-reset-password/assets/icon-256x256.png?rev=3445607\";}s:12:\"preview_link\";s:0:\"\";s:4:\"Name\";s:23:\"Frontend Reset Password\";}s:8:\"meta-box\";a:35:{s:4:\"name\";s:8:\"Meta Box\";s:4:\"slug\";s:8:\"meta-box\";s:7:\"version\";s:6:\"5.11.1\";s:6:\"author\";s:62:\"<a href=\"https://profiles.wordpress.org/metabox/\">Meta Box</a>\";s:14:\"author_profile\";s:39:\"https://profiles.wordpress.org/metabox/\";s:12:\"contributors\";a:8:{s:8:\"elightup\";a:3:{s:7:\"profile\";s:40:\"https://profiles.wordpress.org/elightup/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/60eb84ca87c9306e25eeab170d40ca8249c02520cc62de5e8379418370d2da69?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:8:\"eLightUp\";}s:7:\"metabox\";a:3:{s:7:\"profile\";s:39:\"https://profiles.wordpress.org/metabox/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/6df340d4915dd651839cc861a5922b341388cb10fa04d9103b9666001562b6e5?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:8:\"Meta Box\";}s:6:\"rilwis\";a:3:{s:7:\"profile\";s:38:\"https://profiles.wordpress.org/rilwis/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/64b51769e7b80312023eb6c3f766cb512cf79adf7265812b15442f9573a9a056?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:8:\"Anh Tran\";}s:10:\"f-j-kaiser\";a:3:{s:7:\"profile\";s:42:\"https://profiles.wordpress.org/f-j-kaiser/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/d9c008fd64a3526ac866412147cc49d22214d763db1bd86e817995d3aa9f1823?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:18:\"Franz Josef Kaiser\";}s:11:\"funkatronic\";a:3:{s:7:\"profile\";s:43:\"https://profiles.wordpress.org/funkatronic/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/35e97a8a6a16cf83a8c3fe86cfb13429c092546ee7c1af870c707f55aaf62df4?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:15:\"Manny Fleurmond\";}s:12:\"perwiklander\";a:3:{s:7:\"profile\";s:44:\"https://profiles.wordpress.org/perwiklander/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/a06e62e9a279e1042610df13f67ce85d99d4c6d6438dfb532427548bd26b955a?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:13:\"Per Wiklander\";}s:7:\"ruanmer\";a:3:{s:7:\"profile\";s:39:\"https://profiles.wordpress.org/ruanmer/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/f76f3d2facc688a4a0099f2dfb50adda3349131630a7c0cb6b864501f30affc3?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:7:\"ruanmer\";}s:5:\"tanng\";a:3:{s:7:\"profile\";s:37:\"https://profiles.wordpress.org/tanng/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/995684b65c6be89e1f78e19af18ad635edccb533d15c5d4be165761f9592effe?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:10:\"Tan Nguyen\";}}s:8:\"requires\";s:3:\"6.5\";s:6:\"tested\";s:5:\"6.9.1\";s:12:\"requires_php\";s:3:\"7.1\";s:16:\"requires_plugins\";a:0:{}s:6:\"rating\";i:96;s:7:\"ratings\";a:5:{i:5;i:147;i:4;i:8;i:3;i:1;i:2;i:1;i:1;i:4;}s:11:\"num_ratings\";i:161;s:11:\"support_url\";s:46:\"https://wordpress.org/support/plugin/meta-box/\";s:15:\"support_threads\";i:1;s:24:\"support_threads_resolved\";i:1;s:15:\"active_installs\";i:500000;s:12:\"last_updated\";s:21:\"2026-02-02 7:54am GMT\";s:5:\"added\";s:10:\"2011-11-07\";s:8:\"homepage\";s:18:\"https://metabox.io\";s:8:\"sections\";a:5:{s:11:\"description\";s:12003:\"<h3>WordPress custom fields plugin</h3>\n<p><a href=\"https://metabox.io\" rel=\"nofollow ugc\">Meta Box</a> is a professional framework that makes building and customizing a website with dynamic data and content in WordPress fun and easy.</p>\n<p>Meta Box helps you add <a href=\"https://metabox.io/series/custom-fields/\" rel=\"nofollow ugc\">custom fields</a> and dynamic data to posts, pages, custom post types, forms and anywhere you want using over 40+ different field types such as text, images, file upload, checkboxes, and more.</p>\n<p>On top of that, each WordPress custom field type has extensive internal options for unlimited content possibilities. Complete customization and control is just a few clicks away.</p>\n<blockquote>\n<p><strong>Meta Box Lite</strong><br />\n  We recommend using <a href=\"https://metabox.io/lite/\" rel=\"nofollow ugc\">Meta Box Lite</a>, a feature-rich free UI version of Meta Box that provides UI and all free features for managing custom fields and dynamic content on WordPress, including post types, taxonomies, custom fields, and relationships.</p>\n</blockquote>\n<h3>Create any type of custom fields in WordPress</h3>\n<p>That&#8217;s right – any type. No matter where you need to insert custom data and features, Meta Box&#8217;s WordPress custom fields have your back, and with infinite options to boot.</p>\n<p><strong>Here are just a few of the data types you can customize:</strong></p>\n<ul>\n<li>Posts</li>\n<li>Pages</li>\n<li>Custom post types (you can also use our free plugin <a href=\"https://metabox.io/plugins/custom-post-type/\" rel=\"nofollow ugc\">MB Custom Post Types &amp; Custom Taxonomies</a> to create custom post types and custom taxonomies)</li>\n<li><a href=\"https://metabox.io/plugins/mb-term-meta/\" rel=\"nofollow ugc\">Taxonomies</a></li>\n<li><a href=\"https://metabox.io/plugins/mb-settings-page/\" rel=\"nofollow ugc\">Settings pages or Customizer sections</a></li>\n<li><a href=\"https://metabox.io/plugins/mb-user-profile/\" rel=\"nofollow ugc\">User profile pages</a></li>\n<li><a href=\"https://metabox.io/plugins/mb-comment-meta/\" rel=\"nofollow ugc\">Post comments</a></li>\n</ul>\n<h3>A wide-range of field types and options</h3>\n<p>Take your standard WordPress custom field and imagine it infinitely expanded. That&#8217;s how many options Meta Box gives you:</p>\n<ul>\n<li>Meta Box supports <a href=\"https://docs.metabox.io/fields/\" rel=\"nofollow ugc\">40+ built-in WordPress custom field types</a> for all your needs including text, textarea, WYSIWYG editor, image, file, post, select, checkbox, radio buttons, date/time picker, taxonomy, user, oembed and more to come.</li>\n<li>Not enough? You can also <a href=\"https://docs.metabox.io/custom-field-type/\" rel=\"nofollow ugc\">effortlessly create your own field type</a>.</li>\n<li>Meta Box supports cloning fields for most field types including the WYSIWYG editor field. It also supports <a href=\"https://metabox.io/plugins/meta-box-group/\" rel=\"nofollow ugc\">repeatable field groups</a>.</li>\n</ul>\n<h3>It&#8217;s developer-friendly</h3>\n<p>As a developer, you have enough on your plate. You shouldn&#8217;t have to create an entirely new system for each project. Use Meta Box to your full advantage.</p>\n<p>You can use Meta Box and its custom fields for any custom post type in WordPress on as many websites as you want so you can use it on client projects as well.</p>\n<ul>\n<li>Has an ultra-lightweight, yet powerful API that won&#8217;t overload your site.</li>\n<li>Add only what you need instead of getting stuck with a bundle of features you don&#8217;t even want that bloat your site.</li>\n<li>Meta Box <a href=\"https://docs.metabox.io/integration/\" rel=\"nofollow ugc\">easily integrates with any theme and plugin</a>, and supports Composer!</li>\n<li>We use the <a href=\"https://docs.metabox.io/database/\" rel=\"nofollow ugc\">native WordPress meta data storage</a> and functions for ease of use and lightning-fast processing.</li>\n<li>Has a lot of <a href=\"https://docs.metabox.io/category/actions/\" rel=\"nofollow ugc\">actions</a> and <a href=\"https://docs.metabox.io/category/filters/\" rel=\"nofollow ugc\">filters</a> so you can build or change a site&#8217;s appearance and behavior in the plugin.</li>\n</ul>\n<h3>Don&#8217;t love coding? You&#8217;re in luck!</h3>\n<p>If you prefer a more visual system to create custom fields in WordPress, please use <a href=\"https://metabox.io/lite/\" rel=\"nofollow ugc\">Meta Box Lite</a>, a feature-rich free UI version of Meta Box that provides:</p>\n<ul>\n<li>All the power of Meta Box without touching a single line of code.</li>\n<li>Designer-friendly, lightweight and work at top-notch speeds.</li>\n<li>Export your custom fields and settings to PHP. Then, add it to a new site without needing to install this extension for an incredibly lightweight option.</li>\n</ul>\n<h3>Gratis extensies</h3>\n<ul>\n<li>Migrations from <a href=\"https://metabox.io/plugins/mb-acf-migration/\" rel=\"nofollow ugc\">ACF</a> or <a href=\"https://metabox.io/plugins/mb-toolset-migration/\" rel=\"nofollow ugc\">Toolset</a>.</li>\n<li>Integrations with all page builder plugins like <a href=\"https://metabox.io/plugins/mb-elementor-integrator/\" rel=\"nofollow ugc\">Elementor</a>, <a href=\"https://metabox.io/plugins/meta-box-beaver-themer-integrator/\" rel=\"nofollow ugc\">Beaver Builder</a>, Divi, Bricks, Brizy, etc.</li>\n<li>Integrations with SEO plugins like <a href=\"https://wordpress.org/plugins/meta-box-yoast-seo/\" rel=\"ugc\">Yoast SEO</a>, <a href=\"https://metabox.io/plugins/mb-rank-math/\" rel=\"nofollow ugc\">Rank Math</a>, or Slim SEO.</li>\n<li><a href=\"https://metabox.io/plugins/meta-box-builder/\" rel=\"nofollow ugc\">MB Builder</a>: Create custom meta boxes and custom fields in WordPress using a user-friendly drag-and-drop interface.</li>\n<li><a href=\"https://metabox.io/plugins/mb-comment-meta/\" rel=\"nofollow ugc\">MB Comment Meta</a>: Add WordPress custom fields to comments in WordPress.</li>\n<li><a href=\"https://metabox.io/plugins/custom-post-type/\" rel=\"nofollow ugc\">MB Custom Post Types &amp; Custom Taxonomies</a>: Create and manage custom post types and taxonomies with UI.</li>\n<li><a href=\"https://wordpress.org/plugins/mb-relationships/\" rel=\"ugc\">MB Relationships</a>: Create as many connections as you want from post-to-post or page-to-page.</li>\n<li><a href=\"https://metabox.io/plugins/mb-rest-api/\" rel=\"nofollow ugc\">MB Rest API</a>: Pull all meta values from posts and terms into the WP REST API responses.</li>\n<li><a href=\"https://metabox.io/plugins/meta-box-facetwp-integrator/\" rel=\"nofollow ugc\">MB FacetWP Integrator</a>: Integrates Meta Box and FacetWP to make custom fields searchable and filterable.</li>\n<li><a href=\"https://wordpress.org/plugins/meta-box-text-limiter/\" rel=\"ugc\">MB Text Limiter</a>: Limit the number of characters or words entered for text and textarea fields.</li>\n</ul>\n<h3>Premium Extensions</h3>\n<ul>\n<li><a href=\"https://metabox.io/plugins/mb-admin-columns/\" rel=\"nofollow ugc\">MB Admin Columns</a>: Display WordPress custom fields in table columns in admin.</li>\n<li><a href=\"https://metabox.io/plugins/mb-blocks/\" rel=\"nofollow ugc\">MB Blocks</a>: Create custom Gutenberg blocks with PHP, using the same syntax in Meta Box.</li>\n<li><a href=\"https://metabox.io/plugins/meta-box-columns/\" rel=\"nofollow ugc\">MB Columns</a>: Display eye-catching custom fields in WordPress by putting them into 12-column grids.</li>\n<li><a href=\"https://metabox.io/plugins/meta-box-conditional-logic/\" rel=\"nofollow ugc\">MB Conditional Logic</a>: Add visibility dependency for custom meta boxes and custom fields in WordPress.</li>\n<li><a href=\"https://metabox.io/plugins/mb-custom-table/\" rel=\"nofollow ugc\">MB Custom Table</a>: Save custom fields to custom tables instead of the default meta tables to reduce your database&#8217;s size and increase its performance.</li>\n<li><a href=\"https://metabox.io/plugins/mb-frontend-submission/\" rel=\"nofollow ugc\">MB Frontend Submission</a>: Create frontend forms for users to submit posts.</li>\n<li><a href=\"https://metabox.io/plugins/meta-box-geolocation/\" rel=\"nofollow ugc\">MB Geolocation</a>: Automatically and instantly populate location data with the power of the Google Maps Geolocation API.</li>\n<li><a href=\"https://metabox.io/plugins/meta-box-group/\" rel=\"nofollow ugc\">MB Group</a>: Create repeatable groups for better appearance and structure.</li>\n<li><a href=\"https://metabox.io/plugins/meta-box-include-exclude/\" rel=\"nofollow ugc\">MB Include Exclude</a>: Show or hide meta boxes by ID, page template, taxonomy, or custom function.</li>\n<li><a href=\"https://metabox.io/plugins/mb-revision/\" rel=\"nofollow ugc\">MB Revision</a>: Track changes to custom fields in WordPress with revisions. You can compare and restore the changes smoothly.</li>\n<li><a href=\"https://metabox.io/plugins/mb-settings-page/\" rel=\"nofollow ugc\">MB Settings Page</a>: Create settings pages for themes, plugins or websites with beautiful syntax.</li>\n<li><a href=\"https://metabox.io/plugins/meta-box-show-hide-javascript/\" rel=\"nofollow ugc\">MB Show Hide</a>: Toggle meta boxes by page template, post format, taxonomy and category.</li>\n<li><a href=\"https://metabox.io/plugins/meta-box-tabs/\" rel=\"nofollow ugc\">MB Tabs</a>: Painlessly create tabs for meta boxes with multiple styles and icons.</li>\n<li><a href=\"https://metabox.io/plugins/meta-box-template/\" rel=\"nofollow ugc\">MB Template</a>: Make defining custom meta boxes and WordPress custom fields way easier with templates.</li>\n<li><a href=\"https://metabox.io/plugins/mb-term-meta/\" rel=\"nofollow ugc\">MB Term Meta</a>: Add custom fields to categories, tags or custom taxonomies.</li>\n<li><a href=\"https://metabox.io/plugins/meta-box-tooltip/\" rel=\"nofollow ugc\">MB Tooltip</a>: Display help information for custom fields with tooltips.</li>\n<li><a href=\"https://metabox.io/plugins/mb-user-meta/\" rel=\"nofollow ugc\">MB User Meta</a>: Add custom fields to users.</li>\n<li><a href=\"https://metabox.io/plugins/mb-user-profile/\" rel=\"nofollow ugc\">MB User Profile</a>: Build login, register and edit profile forms for users.</li>\n<li><a href=\"https://metabox.io/plugins/mb-views/\" rel=\"nofollow ugc\">MB Views</a>: Outputting custom fields and build front-end templates for WordPress without touching theme files.</li>\n</ul>\n<h3>Gedetailleerde documentatie</h3>\n<p>We provide regularly updated, and extensive <a href=\"https://docs.metabox.io\" rel=\"nofollow ugc\">documentation</a> as well as <a href=\"https://docs.metabox.io/tutorials/\" rel=\"nofollow ugc\">tutorials</a> on how to use MetaBox and custom fields in WordPress to your advantage as well as in the most efficient way possible.</p>\n<p>Here are a few guides to quickly get you started with Meta Box and creating your own WordPress custom fields:</p>\n<ul>\n<li><a href=\"https://docs.metabox.io/introduction/\" rel=\"nofollow ugc\">Introduction</a></li>\n<li><a href=\"https://docs.metabox.io/custom-post-types/\" rel=\"nofollow ugc\">Custom post types</a></li>\n<li><a href=\"https://docs.metabox.io/custom-fields/\" rel=\"nofollow ugc\">Custom fields</a></li>\n<li><a href=\"https://docs.metabox.io/field-settings/\" rel=\"nofollow ugc\">Field settings</a></li>\n<li><a href=\"https://docs.metabox.io/displaying-fields-with-code/\" rel=\"nofollow ugc\">Displaying fields</a></li>\n</ul>\n<h3>You might also like</h3>\n<p>If you like this plugin, you might also like our other WordPress products:</p>\n<ul>\n<li><a href=\"https://wpslimseo.com\" rel=\"nofollow ugc\">Slim SEO</a> &#8211; A fast, lightweight and full-featured SEO plugin for WordPress with minimal configuration.</li>\n<li><a href=\"https://wpfalcon.pro\" rel=\"nofollow ugc\">Falcon</a> &#8211; A lightweight companion for making WordPress faster, cleaner, and more secure.</li>\n<li><a href=\"https://gretathemes.com\" rel=\"nofollow ugc\">GretaThemes</a> &#8211; Free and premium WordPress themes that clean, simple and just work.</li>\n<li><a href=\"https://wpautolistings.com\" rel=\"nofollow ugc\">Auto Listings</a> &#8211; A car sale and dealership plugin for WordPress.</li>\n</ul>\n\";s:12:\"installation\";s:887:\"<p>We recommend using <a href=\"https://metabox.io/lite/\" rel=\"nofollow ugc\">Meta Box Lite</a>, a feature-rich free UI version of Meta Box that provides UI and all free features for managing custom fields and dynamic content on WordPress, including post types, taxonomies, custom fields, and relationships.</p>\n<p>To install Meta Box Lite, go to <a href=\"https://metabox.io/lite/\" rel=\"nofollow ugc\">this page</a> and download it.</p>\n<p>If you want to use Meta Box, please follow these steps:</p>\n<ol>\n<li>Visit <strong>Plugins &gt; Add New</strong> inside your WordPress dashboard</li>\n<li>Search for <strong>Meta Box</strong></li>\n<li>Click the <strong>Install Now</strong> button to install the plugin</li>\n<li>Click the <strong>Activate</strong> button to activate the plugin</li>\n</ol>\n<p><a href=\"https://docs.metabox.io/introduction/\" rel=\"nofollow ugc\">Get started here</a>.</p>\n\";s:9:\"changelog\";s:5013:\"<h4>5.11.1 &#8211; 2026-02-02</h4>\n<p><strong>Improvements for the block editor field:</strong></p>\n<ul>\n<li>Add block inspector sidebar</li>\n<li>Add structure panel to show the list view of blocks</li>\n<li>Add fullscreen mode</li>\n<li>Add <code>height</code> settings (default is <code>300px</code>) and allow resizing the editor</li>\n</ul>\n<p><strong>Fixes for the block editor field:</strong></p>\n<ul>\n<li>Fix cannot upload images for the image block</li>\n<li>Fix blank site editor when using the block editor field</li>\n<li>Fix custom rich text formats not working</li>\n<li>Fix conflicts with <code>image_advanced</code> and <code>file_advanced</code> fields</li>\n</ul>\n<p>** Other changes:**</p>\n<ul>\n<li>Fix cannot create new terms with required date/time fields</li>\n</ul>\n<h4>5.11.0 &#8211; 2026-01-15</h4>\n<ul>\n<li>Add new field type: <code>block_editor</code>. See more details on our <a href=\"https://metabox.io/block-editor-field-type/\" rel=\"nofollow ugc\">blog post</a> and <a href=\"https://docs.metabox.io/fields/block-editor/\" rel=\"nofollow ugc\">documentation</a>.</li>\n</ul>\n<h4>5.10.19 &#8211; 2025-11-24</h4>\n<ul>\n<li>Fix the <code>use</code> statement with non-compound name has no effect</li>\n</ul>\n<h4>5.10.18 &#8211; 2025-11-24</h4>\n<ul>\n<li>Fix deprecation message for <code>datetime</code> field</li>\n</ul>\n<h4>5.10.17 &#8211; 2025-11-07</h4>\n<ul>\n<li>WPML integration: fix error when filtering value for helper functions when no fields are found.</li>\n</ul>\n<h4>5.10.16 &#8211; 2025-11-05</h4>\n<ul>\n<li>WPML integration: filter helper functions to get the translated IDs for <code>post</code> field</li>\n<li>Fix cloning <code>post</code> field not clearing the value</li>\n</ul>\n<h4>5.10.15 &#8211; 2025-10-06</h4>\n<ul>\n<li>Add <code>marker_draggable</code> option for <code>map</code>/<code>osm</code> fields to disable changing the pin on the map.</li>\n</ul>\n<h4>5.10.14 &#8211; 2025-09-15</h4>\n<ul>\n<li>Update dependencies</li>\n</ul>\n<h4>5.10.13 &#8211; 2025-08-14</h4>\n<ul>\n<li>Fix <code>get_current_screen()</code> error for term meta</li>\n</ul>\n<h4>5.10.12 &#8211; 2025-08-13</h4>\n<ul>\n<li>Fix Open Street Maps field not showing (sometimes) with conditional logic</li>\n<li>Enqueue assets for the iframed editor, to make all fields are rendered properly in the iframed editor</li>\n</ul>\n<h4>5.10.11 &#8211; 2025-07-15</h4>\n<p>Fix validation for blocks</p>\n<h4>5.10.10 &#8211; 2025-05-21</h4>\n<ul>\n<li>Fix datetime field returns null</li>\n<li>Fix single image field not working with Polylang Pro</li>\n<li>Fix reveal password icon not working</li>\n</ul>\n<h4>5.10.9 &#8211; 2025-05-08</h4>\n<ul>\n<li>Add button to toggle password (#1630)</li>\n<li>Add gesture handling support for OSM field (#1631)</li>\n<li>Datetime &amp; select2: use user&#8217;s locale instead of site&#8217;s locale</li>\n</ul>\n<h4>5.10.8 &#8211; 2025-03-14</h4>\n<ul>\n<li>Redesign the dashboard</li>\n</ul>\n<h4>5.10.7 &#8211; 2025-02-25</h4>\n<ul>\n<li>Fix: max clone with clone empty start</li>\n</ul>\n<h4>5.10.6 &#8211; 2025-01-11</h4>\n<ul>\n<li>Fix validation for dash ids</li>\n<li>Fix datetime fields not showing inline picker inside groups</li>\n<li>Fix <code>label_description</code> not working for <code>fieldset_text</code></li>\n<li>Fix field label div still show when no field name but with <code>label_description</code></li>\n<li>Remove <code>image_select</code> field&#8217;s JS, styling with CSS only</li>\n<li>Add gap for key value inputs</li>\n</ul>\n<h4>5.10.5 &#8211; 2024-12-16</h4>\n<ul>\n<li>Make validation for add new terms work</li>\n<li>Improve styling of meta boxes on the sidebar in the block editor</li>\n<li>Improve style of input with prepend and append</li>\n<li>Fix maps/osm fields and geolocation not working with subfields in groups</li>\n<li>Fix select advanced becomes normal select with cloneable setting</li>\n<li>Fix validation</li>\n</ul>\n<h4>5.10.4 &#8211; 2024-11-20</h4>\n<ul>\n<li>OSM/Map fields: add support for select field type</li>\n<li>Add <code>$url</code> to <code>rwmb_oembed_not_available_string</code> filter</li>\n<li>Small CSS improvements for file input, background &amp; button group</li>\n<li>Fix not returning value for helper functions for images saving in a custom folder and using a custom table</li>\n</ul>\n<h4>5.10.3 &#8211; 2024-10-30</h4>\n<ul>\n<li>fix: std after saving</li>\n<li>fix: field set text save empty values</li>\n<li>fix: subfield&#8217;s id</li>\n</ul>\n<h4>5.10.2 &#8211; 2024-09-26</h4>\n<ul>\n<li>Fix issue with conditional logic</li>\n<li>Fix error when removing default taxonomy meta box in the front end or with the block editor</li>\n<li>Fix missing .hidden on the front end for <code>checkbox_tree</code></li>\n<li>Fix required attribute for <code>select_tree</code></li>\n</ul>\n<h4>5.10.1 &#8211; 2024-09-07</h4>\n<ul>\n<li>Fix issue with <code>clone_empty_start</code> (validation, now showing data for the 1st clone, broken <code>text_list</code> field, etc.)</li>\n</ul>\n<p><a href=\"https://metabox.io/changelog/\" rel=\"nofollow ugc\">See full changelog here</a>.</p>\n\";s:11:\"screenshots\";s:1229:\"<ol><li><a href=\"https://ps.w.org/meta-box/assets/screenshot-1.png?rev=1626382\"><img src=\"https://ps.w.org/meta-box/assets/screenshot-1.png?rev=1626382\" alt=\"Tekstvelden\"></a><p>Tekstvelden</p></li><li><a href=\"https://ps.w.org/meta-box/assets/screenshot-2.png?rev=1626382\"><img src=\"https://ps.w.org/meta-box/assets/screenshot-2.png?rev=1626382\" alt=\"Basic Fields\"></a><p>Basic Fields</p></li><li><a href=\"https://ps.w.org/meta-box/assets/screenshot-3.png?rev=1626382\"><img src=\"https://ps.w.org/meta-box/assets/screenshot-3.png?rev=1626382\" alt=\"Advanced Fields\"></a><p>Advanced Fields</p></li><li><a href=\"https://ps.w.org/meta-box/assets/screenshot-4.png?rev=1626382\"><img src=\"https://ps.w.org/meta-box/assets/screenshot-4.png?rev=1626382\" alt=\"File Image Upload Fields\"></a><p>File Image Upload Fields</p></li><li><a href=\"https://ps.w.org/meta-box/assets/screenshot-5.png?rev=1626382\"><img src=\"https://ps.w.org/meta-box/assets/screenshot-5.png?rev=1626382\" alt=\"Media Fields\"></a><p>Media Fields</p></li><li><a href=\"https://ps.w.org/meta-box/assets/screenshot-6.png?rev=1626382\"><img src=\"https://ps.w.org/meta-box/assets/screenshot-6.png?rev=1626382\" alt=\"Post Taxonomy Fields\"></a><p>Post Taxonomy Fields</p></li></ol>\";s:7:\"reviews\";s:16435:\"<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Best Performance and works with Breakdance Visual Builder</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/alamea/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/05e34df4bdd0930cbe0174610ba3cec16961a88a7a6dfe6adf98bc869db826f1?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/05e34df4bdd0930cbe0174610ba3cec16961a88a7a6dfe6adf98bc869db826f1?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/alamea/\" class=\"reviewer-name\">alamea <small>(Alamea)</small></a> op <span class=\"review-date\">oktober 26, 2025</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>The performance is impressive, and the plugin is constantly maintained. It\'s especially nice that it works seamlessly with Breakdance Visual Builder. Thanks to sample code from Metabox (thanks for the excellent documentation), I was finally able to configure a relationship I hadn\'t been able to get past on my own.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Outstanding Plugin and Incredible Support!</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/zentyx/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/41a043870b296e9420a1ef5da67460a49be08dc95e3dcd297e492fda5b416db1?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/41a043870b296e9420a1ef5da67460a49be08dc95e3dcd297e492fda5b416db1?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/zentyx/\" class=\"reviewer-name\">zentyx</a> op <span class=\"review-date\">juli 5, 2025</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>MetaBox has been a game-changer for my WordPress development workflow. The usability is intuitive and highly functional — everything just makes sense and works seamlessly. What truly sets MetaBox apart, though, is the customer support. It\'s hands down some of the best I’ve ever experienced. Fast, knowledgeable, and genuinely helpful. Highly recommended for anyone looking for a powerful and flexible custom fields plugin.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Not for admin</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"1 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"1\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/dtrim/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/6dc7e69d6f9d24196c7d6c337d697a67992bf2f96361c72c564864969fd298ba?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/6dc7e69d6f9d24196c7d6c337d697a67992bf2f96361c72c564864969fd298ba?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/dtrim/\" class=\"reviewer-name\">Dan <small>(dtrim)</small></a> op <span class=\"review-date\">november 15, 2024</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Looks like it\'s free to use in the admin but you have to pay for that.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Moved from Toolset - so far so good</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/psudan/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/890867096b278e0610028b8601534275e47cb675460096ec33fccd02a37fc032?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/890867096b278e0610028b8601534275e47cb675460096ec33fccd02a37fc032?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/psudan/\" class=\"reviewer-name\">psudan</a> op <span class=\"review-date\">oktober 3, 2024</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>I loved the Views and Conditional shortcode in Toolset. MB Views is good but not as user friendly, missing the conditional shortocde. On the other hand the Settings page in MB is great</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Overall very happy with my move - integration with Bricks Builder is great!<br /><br /></p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Lightweight and Powerful - Best on Market</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/woocomuser/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/f1641c982381ae537ceeb0630788a5c906fd54c4874cae7354a3f9824d1f10cf?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/f1641c982381ae537ceeb0630788a5c906fd54c4874cae7354a3f9824d1f10cf?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/woocomuser/\" class=\"reviewer-name\">justauser034675 <small>(woocomuser)</small></a> op <span class=\"review-date\">september 13, 2024</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Meta Box has always been a great a plugin and they\'re still pushing great updates and fixes fast. Support is excellent, even with technical and custom development.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Lightweight</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/lunarboy/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/443fa4a134ff2278ddf46ed0d8ba60807291e1525edd0d18afb4c30f2ec53b62?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/443fa4a134ff2278ddf46ed0d8ba60807291e1525edd0d18afb4c30f2ec53b62?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/lunarboy/\" class=\"reviewer-name\">lunarboy</a> op <span class=\"review-date\">augustus 20, 2024</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>It\'s lightweight and works great.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Perfect tool, even better support</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/evenue/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/8089559ccf2664c492ba2f5753d454beaf5085d098baa7a4900c576e8b68ae38?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/8089559ccf2664c492ba2f5753d454beaf5085d098baa7a4900c576e8b68ae38?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/evenue/\" class=\"reviewer-name\">evenue</a> op <span class=\"review-date\">augustus 16, 2024</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>I already wrote everything in the title, using WP with Meta Box is a whole other thing, in this way WP becomes a powerful development tool</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Furthermore, the assistance (commercial and technical) is really very efficient<br />Good guys!</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Perfect and much lighter than ACF</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/stefk64/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/2a979411f5b6c8fffc4d1edadddffb967072e3d8303ac08f75e39b69085afa79?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/2a979411f5b6c8fffc4d1edadddffb967072e3d8303ac08f75e39b69085afa79?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/stefk64/\" class=\"reviewer-name\">stefk64</a> op <span class=\"review-date\">augustus 5, 2024</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>very good plugin for custom menu and cunstom field. Much faster than ACF</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Great support</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/growtogive/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/7e7e6f399ab13d591143f59fae7810eca3bb63b0e8e62febc5711be2b311a37e?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/7e7e6f399ab13d591143f59fae7810eca3bb63b0e8e62febc5711be2b311a37e?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/growtogive/\" class=\"reviewer-name\">James <small>(growtogive)</small></a> op <span class=\"review-date\">augustus 3, 2024</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>I\'m excited about the features of this plugin. And so far the support has been excellent.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Outstanding Support and Excellent Tools for WordPress Users!</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/siradj85/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/f9fe4f4475cade06a6d1ab770290029dfbe9f7df44ac63bb9fb03d90d483a7e1?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/f9fe4f4475cade06a6d1ab770290029dfbe9f7df44ac63bb9fb03d90d483a7e1?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/siradj85/\" class=\"reviewer-name\">siradj85</a> op <span class=\"review-date\">juli 22, 2024</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>I want to express my gratitude for the excellent service provided by Meta Box. The platform offers fantastic tools that enhance my WordPress experience, and the support team is exceptional. They were quick to respond and very helpful in resolving my licensing issue. Their dedication to customer satisfaction is evident, and I truly appreciate all their efforts. Thank you, Meta Box, for your great products and support!</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>موقع تعرف كوم</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph --></div>\n</div>\n\";}s:17:\"short_description\";s:148:\"Meta Box plugin is a powerful, professional developer toolkit to create custom meta boxes and custom fields for your custom post types in WordPress.\";s:13:\"download_link\";s:58:\"https://downloads.wordpress.org/plugin/meta-box.5.11.1.zip\";s:14:\"upgrade_notice\";a:0:{}s:11:\"screenshots\";a:6:{i:1;a:2:{s:3:\"src\";s:61:\"https://ps.w.org/meta-box/assets/screenshot-1.png?rev=1626382\";s:7:\"caption\";s:11:\"Tekstvelden\";}i:2;a:2:{s:3:\"src\";s:61:\"https://ps.w.org/meta-box/assets/screenshot-2.png?rev=1626382\";s:7:\"caption\";s:12:\"Basic Fields\";}i:3;a:2:{s:3:\"src\";s:61:\"https://ps.w.org/meta-box/assets/screenshot-3.png?rev=1626382\";s:7:\"caption\";s:15:\"Advanced Fields\";}i:4;a:2:{s:3:\"src\";s:61:\"https://ps.w.org/meta-box/assets/screenshot-4.png?rev=1626382\";s:7:\"caption\";s:24:\"File Image Upload Fields\";}i:5;a:2:{s:3:\"src\";s:61:\"https://ps.w.org/meta-box/assets/screenshot-5.png?rev=1626382\";s:7:\"caption\";s:12:\"Media Fields\";}i:6;a:2:{s:3:\"src\";s:61:\"https://ps.w.org/meta-box/assets/screenshot-6.png?rev=1626382\";s:7:\"caption\";s:20:\"Post Taxonomy Fields\";}}s:4:\"tags\";a:5:{s:13:\"custom-fields\";s:13:\"custom fields\";s:17:\"custom-post-types\";s:17:\"custom post types\";s:17:\"custom-taxonomies\";s:17:\"Custom Taxonomies\";s:8:\"meta-box\";s:8:\"meta box\";s:9:\"post-type\";s:9:\"post type\";}s:8:\"versions\";a:204:{s:6:\"4.1.10\";s:58:\"https://downloads.wordpress.org/plugin/meta-box.4.1.10.zip\";s:6:\"4.1.11\";s:58:\"https://downloads.wordpress.org/plugin/meta-box.4.1.11.zip\";s:4:\"4.10\";s:56:\"https://downloads.wordpress.org/plugin/meta-box.4.10.zip\";s:6:\"4.10.1\";s:58:\"https://downloads.wordpress.org/plugin/meta-box.4.10.1.zip\";s:6:\"4.10.2\";s:58:\"https://downloads.wordpress.org/plugin/meta-box.4.10.2.zip\";s:6:\"4.10.3\";s:58:\"https://downloads.wordpress.org/plugin/meta-box