}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"Blog – WordPress.org Nederlands\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"https://nl.wordpress.org\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"width\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:6:\"height\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}s:4:\"item\";a:10:{i:0;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:42:\"WordPress 6.7 “Rollins” is beschikbaar\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"https://nl.wordpress.org/2024/11/12/wordpress-6-7-rollins-is-beschikbaar/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:81:\"https://nl.wordpress.org/2024/11/12/wordpress-6-7-rollins-is-beschikbaar/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 12 Nov 2024 22:23:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"Release\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://nl.wordpress.org/?p=1408\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:358:\"WordPress 6.7 introduceert het moderne Twenty Twenty-Five thema dat ultieme ontwerpflexibiliteit biedt voor elke blog op elke schaal. Beheer je site typografie als nooit tevoren met nieuwe lettertype beheerfuncties. De nieuwe Zoom Out functie stelt je in staat om je site met een macroblik te ontwerpen, afstand te nemen van de details en het grote [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Remkus de Vries\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:9708:\"\n<p class=\"wp-block-paragraph\">WordPress 6.7 introduceert het moderne Twenty Twenty-Five thema dat ultieme ontwerpflexibiliteit biedt voor elke blog op elke schaal. Beheer je site typografie als nooit tevoren met nieuwe lettertype beheerfuncties. De nieuwe Zoom Out functie stelt je in staat om je site met een macroblik te ontwerpen, afstand te nemen van de details en het grote geheel tot leven te brengen.</p>\n\n\n\n<h2 class=\"wp-block-heading has-huge-font-size\">Introductie van Twenty Twenty-Five</h2>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"wp-block-paragraph\"><strong>Eindeloze mogelijkheid zonder complexiteit</strong><br>Twenty twenty-five biedt een flexibel, ontwerpgericht thema waarmee je eenvoudig verbluffende sites kunt bouwen. Pas je esthetiek aan met een reeks stijlopties, blokpatronen en kleurenpaletten. Teruggebracht tot de essentie, is dit een thema dat echt met je kan meegroeien.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><a href=\"https://nl.wordpress.org/files/2025/02/image.png\"><img fetchpriority=\"high\" decoding=\"async\" width=\"900\" height=\"900\" src=\"https://nl.wordpress.org/files/2025/02/image.png\" alt=\"\" class=\"wp-image-1409\" srcset=\"https://nl.wordpress.org/files/2025/02/image.png 900w, https://nl.wordpress.org/files/2025/02/image-300x300.png 300w, https://nl.wordpress.org/files/2025/02/image-150x150.png 150w, https://nl.wordpress.org/files/2025/02/image-768x768.png 768w\" sizes=\"(max-width: 900px) 100vw, 900px\" /></a></figure>\n</div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading has-huge-font-size\">Krijg het grote geheel met Zoom Out</h2>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><a href=\"https://nl.wordpress.org/files/2025/02/image-1.png\"><img decoding=\"async\" width=\"900\" height=\"900\" src=\"https://nl.wordpress.org/files/2025/02/image-1.png\" alt=\"\" class=\"wp-image-1411\" srcset=\"https://nl.wordpress.org/files/2025/02/image-1.png 900w, https://nl.wordpress.org/files/2025/02/image-1-300x300.png 300w, https://nl.wordpress.org/files/2025/02/image-1-150x150.png 150w, https://nl.wordpress.org/files/2025/02/image-1-768x768.png 768w\" sizes=\"(max-width: 900px) 100vw, 900px\" /></a></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"wp-block-paragraph\"><strong>Verken je inhoud vanuit een nieuw perspectief</strong><br>Bewerk en orden hele secties van je inhoud als nooit tevoren. Een breder overzicht van je site stelt je in staat om patronen naar wens toe te voegen, te bewerken, te herschikken of te verwijderen. Omarm je innerlijke architect.</p>\n</div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading has-huge-font-size\">Verbind blokken en aangepaste velden zonder gedoe (of code)</h2>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"wp-block-paragraph\"><strong>Een gestroomlijnde manier om dynamische inhoud te creëren</strong><br>Deze functie introduceert een nieuwe UI voor het verbinden van blokken met aangepaste velden, waardoor de controle over dynamische inhoud direct in de editor komt. Koppel blokken met velden in slechts een paar klikken, wat de flexibiliteit en efficiëntie bij het bouwen verbetert. Je klanten zullen van je houden—alsof ze dat niet al deden.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><a href=\"https://nl.wordpress.org/files/2025/02/image-2.png\"><img decoding=\"async\" width=\"900\" height=\"900\" src=\"https://nl.wordpress.org/files/2025/02/image-2.png\" alt=\"\" class=\"wp-image-1415\" srcset=\"https://nl.wordpress.org/files/2025/02/image-2.png 900w, https://nl.wordpress.org/files/2025/02/image-2-300x300.png 300w, https://nl.wordpress.org/files/2025/02/image-2-150x150.png 150w, https://nl.wordpress.org/files/2025/02/image-2-768x768.png 768w\" sizes=\"(max-width: 900px) 100vw, 900px\" /></a></figure>\n</div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading has-huge-font-size\">Omarm je innerlijke lettertype nerd</h2>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><a href=\"https://nl.wordpress.org/files/2025/02/image-3.png\"><img loading=\"lazy\" decoding=\"async\" width=\"900\" height=\"900\" src=\"https://nl.wordpress.org/files/2025/02/image-3.png\" alt=\"\" class=\"wp-image-1416\" srcset=\"https://nl.wordpress.org/files/2025/02/image-3.png 900w, https://nl.wordpress.org/files/2025/02/image-3-300x300.png 300w, https://nl.wordpress.org/files/2025/02/image-3-150x150.png 150w, https://nl.wordpress.org/files/2025/02/image-3-768x768.png 768w\" sizes=\"auto, (max-width: 900px) 100vw, 900px\" /></a></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"wp-block-paragraph\"><strong>Nieuwe stijl sectie, nieuwe rechten</strong><br>Maak, bewerk, verwijder en pas vooraf gemaakte instellingen voor lettertypen toe met de volgende toevoeging aan de interface stijlen. Pas de standaardinstellingen van het thema aan of maak je eigen aangepaste lettertypegrootte, compleet met vloeiende typografie voor responsive schalen van lettertypen. Het zit &#8216;m in de details!</p>\n</div>\n</div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h2 class=\"wp-block-heading has-huge-font-size\">Prestatie updates</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.7 levert belangrijke prestatie updates, inclusief snellere patroon lading, geoptimaliseerde voorbeelden in de dataviews component, verbeterde PHP 8{+} ondersteuning en verwijdering van verouderde code, automatische groottes voor lazy-loaded afbeeldingen, en efficiëntere tag verwerking in de HTML API.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h2 class=\"wp-block-heading has-huge-font-size\">Toegankelijkheid verbeteringen</h2>\n\n\n\n<p class=\"wp-block-paragraph\">65{+} toegankelijkheidsoplossingen en verbeteringen richten zich op fundamentele aspecten van de WordPress ervaring, van het verbeteren van gebruikersinterface componenten en toetsenbordnavigatie in de editor, tot een toegankelijke koptekst op WordPress loginschermen en duidelijkere labeling overal.</p>\n</div>\n</div>\n\n\n\n<div class=\"wp-block-group has-light-grey-1-background-color has-background is-layout-constrained wp-container-core-group-is-layout-a498d6dd wp-block-group-is-layout-constrained\" style=\"border-radius:10px;padding-top:30px;padding-right:var(--wp--preset--spacing--30);padding-bottom:30px;padding-left:var(--wp--preset--spacing--30)\">\n<h2 class=\"wp-block-heading has-huge-font-size\">En nog veel meer</h2>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:66.66%\">\n<p class=\"wp-block-paragraph\">Voor een uitgebreid overzicht van alle nieuwe functies en verbeteringen in WordPress 6.7 bezoek de feature-showcase site.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:33.33%\">\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"https://wordpress.org/download/releases/6-7/\">Bekijk alles wat nieuw is</a></div>\n</div>\n</div>\n</div>\n</div>\n\n\n\n<hr class=\"wp-block-separator has-text-color has-light-grey-1-color has-alpha-channel-opacity has-light-grey-1-background-color has-background is-style-default\" style=\"margin-top:var(--wp--preset--spacing--60);margin-bottom:var(--wp--preset--spacing--60)\" />\n\n\n\n<h2 class=\"wp-block-heading has-huge-font-size\">Meer leren over WordPress 6.7</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://learn.wordpress.org/\">Learn WordPress</a>&nbsp;is een gratis gegevensbron voor nieuwe en ervaren WordPress gebruikers. Learn staat vol met how-to video&#8217;s over het gebruik van verschillende functies in WordPress,&nbsp;<a href=\"https://learn.wordpress.org/online-workshops/\">interactieve workshops</a>&nbsp;om dieper op onderwerpen in te gaan, en lesplannen om diep in te gaan op specifieke gebieden van WordPress.</p>\n\n\n\n<h4 class=\"wp-block-heading has-extra-large-font-size\"><a href=\"https://wordpress.org/documentation/wordpress-version/version-6-7/\">WordPress 6.7 releaselog</a></h4>\n\n\n\n<p class=\"wp-block-paragraph\">Lees de WordPress 6.7 releaselog voor informatie over installatie, verbeteringen, opgeloste problemen, release bijdragers, leermiddelen en de lijst met bestandswijzigingen.</p>\n\n\n\n<h4 class=\"wp-block-heading has-extra-large-font-size\"><a href=\"https://make.wordpress.org/core/wordpress-6-7-field-guide/\">WordPress 6.7 Field Guide</a></h4>\n\n\n\n<p class=\"wp-block-paragraph\">Verken de WordPress 6.7 Field Guide. Leer over de veranderingen in deze release met gedetailleerde ontwikkelaarsnotities om je te helpen bouwen met WordPress.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:78:\"https://nl.wordpress.org/2024/11/12/wordpress-6-7-rollins-is-beschikbaar/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1408\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"WordPress 6.6 “Dorsey” is beschikbaar\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:72:\"https://nl.wordpress.org/2024/07/17/wordpress-6-6-dorsey-is-beschikbaar/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"https://nl.wordpress.org/2024/07/17/wordpress-6-6-dorsey-is-beschikbaar/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 17 Jul 2024 15:04:03 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"Release\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://nl.wordpress.org/?p=1377\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:438:\"Creëer en implementeer mooie en coherente ontwerpelementen op je sites met WordPress 6.6. Een nieuwe rollback optie voor het automatisch updaten van plugins geeft je controle, flexibiliteit en gemoedsrust. Kleurpaletten &#38; lettertype sets Voeg meer ontwerpopties toe aan elk blokthema. Auteurs van blokthema&#8217;s kunnen onbeperkte individuele kleur of lettertype sets maken om meer specifieke ontwerpmogelijkheden binnen [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Remkus de Vries\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:10612:\"\n<p class=\"wp-block-paragraph\">Creëer en implementeer mooie en coherente ontwerpelementen op je sites met WordPress 6.6. Een nieuwe rollback optie voor het automatisch updaten van plugins geeft je controle, flexibiliteit en gemoedsrust.</p>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-db69df54 wp-block-columns-is-layout-flex\" style=\"margin-top:var(--wp--preset--spacing--50);margin-bottom:var(--wp--preset--spacing--50)\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Kleurpaletten &amp; lettertype sets</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Voeg meer ontwerpopties toe aan elk blokthema.</strong> Auteurs van blokthema&#8217;s kunnen onbeperkte individuele kleur of lettertype sets maken om meer specifieke ontwerpmogelijkheden binnen hetzelfde thema aan te bieden. Deze sets bieden meer beperkte ontwerprechten, waardoor maatwerk mogelijk is zonder de bredere styling van de site te veranderen, buiten kleur of typografie instellingen.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><a href=\"https://nl.wordpress.org/files/2024/07/image.png\"><img loading=\"lazy\" decoding=\"async\" width=\"900\" height=\"900\" src=\"https://nl.wordpress.org/files/2024/07/image.png\" alt=\"\" class=\"wp-image-1378\" srcset=\"https://nl.wordpress.org/files/2024/07/image.png 900w, https://nl.wordpress.org/files/2024/07/image-300x300.png 300w, https://nl.wordpress.org/files/2024/07/image-150x150.png 150w, https://nl.wordpress.org/files/2024/07/image-768x768.png 768w\" sizes=\"auto, (max-width: 900px) 100vw, 900px\" /></a></figure>\n</div>\n</div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-6234225d wp-block-columns-is-layout-flex\" style=\"margin-top:var(--wp--preset--spacing--70);margin-bottom:var(--wp--preset--spacing--70)\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><a href=\"https://nl.wordpress.org/files/2024/07/image-1.png\"><img loading=\"lazy\" decoding=\"async\" width=\"900\" height=\"900\" src=\"https://nl.wordpress.org/files/2024/07/image-1.png\" alt=\"\" class=\"wp-image-1380\" srcset=\"https://nl.wordpress.org/files/2024/07/image-1.png 900w, https://nl.wordpress.org/files/2024/07/image-1-300x300.png 300w, https://nl.wordpress.org/files/2024/07/image-1-150x150.png 150w, https://nl.wordpress.org/files/2024/07/image-1-768x768.png 768w\" sizes=\"auto, (max-width: 900px) 100vw, 900px\" /></a></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Snelle voorbeelden voor pagina&#8217;s</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Vereenvoudig je workflow met een nieuwe lay-out gebouwd voor pagina&#8217;s.</strong>&nbsp;Bekijk al je pagina&#8217;s en een voorbeeld van elke geselecteerde pagina voordat je deze bewerkt via een nieuwe zij-aan-zij lay-out in de Site-editor.</p>\n</div>\n</div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-db69df54 wp-block-columns-is-layout-flex\" style=\"margin-top:var(--wp--preset--spacing--50);margin-bottom:var(--wp--preset--spacing--50)\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Rollbacks voor plugin auto-updates</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Auto-update je plugins met een gerust hart.</strong>&nbsp;Geniet van het gemak van plugin auto-updates met de veiligheid van rollbacks als er iets misgaat, waardoor je site beveiliging verbetert terwijl mogelijke downtime wordt geminimaliseerd.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><a href=\"https://nl.wordpress.org/files/2024/07/image-2.png\"><img loading=\"lazy\" decoding=\"async\" width=\"900\" height=\"900\" src=\"https://nl.wordpress.org/files/2024/07/image-2.png\" alt=\"\" class=\"wp-image-1381\" srcset=\"https://nl.wordpress.org/files/2024/07/image-2.png 900w, https://nl.wordpress.org/files/2024/07/image-2-300x300.png 300w, https://nl.wordpress.org/files/2024/07/image-2-150x150.png 150w, https://nl.wordpress.org/files/2024/07/image-2-768x768.png 768w\" sizes=\"auto, (max-width: 900px) 100vw, 900px\" /></a></figure>\n</div>\n</div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-db69df54 wp-block-columns-is-layout-flex\" style=\"margin-top:var(--wp--preset--spacing--50);margin-bottom:var(--wp--preset--spacing--50)\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><a href=\"https://nl.wordpress.org/files/2024/07/image-3.png\"><img loading=\"lazy\" decoding=\"async\" width=\"900\" height=\"900\" src=\"https://nl.wordpress.org/files/2024/07/image-3.png\" alt=\"\" class=\"wp-image-1382\" srcset=\"https://nl.wordpress.org/files/2024/07/image-3.png 900w, https://nl.wordpress.org/files/2024/07/image-3-300x300.png 300w, https://nl.wordpress.org/files/2024/07/image-3-150x150.png 150w, https://nl.wordpress.org/files/2024/07/image-3-768x768.png 768w\" sizes=\"auto, (max-width: 900px) 100vw, 900px\" /></a></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Synchroniseer</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Voeg de mogelijkheid toe om inhoud in gesynchroniseerde patronen aan te passen.</strong>&nbsp;Sta specifieke stukken inhoud toe om aangepast te worden in elke instantie van een gesynchroniseerd patroon terwijl een consistente stijl voor alle instanties behouden blijft, wat toekomstige updates vereenvoudigt. Momenteel kun je overschrijvingen instellen voor koptekst, paragraaf, knop en afbeelding blokken.</p>\n</div>\n</div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-db69df54 wp-block-columns-is-layout-flex\" style=\"margin-top:var(--wp--preset--spacing--50);margin-bottom:var(--wp--preset--spacing--50)\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Prestatie updates</h3>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.6 bevat belangrijke updates zoals het verwijderen van overbodige&nbsp;<code>WP_Theme_JSON</code>&nbsp;aanroepen, het uitschakelen van autoload voor grote opties, het elimineren van onnodige polyfill afhankelijkheden, lazy-loading van bericht insluitingen, het introduceren van de&nbsp;<code>data-wp-on-async</code>&nbsp;richtlijn en een vermindering van 33% in laadtijd van templates in de editor.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Toegankelijkheid verbeteringen</h3>\n\n\n\n<p class=\"wp-block-paragraph\">55+ toegankelijkheidsoplossingen en verbeteringen richten zich op fundamentele aspecten van de WordPress ervaring, met name de dataviews component die de nieuwe site bewerkingservaring aandrijft en gebieden zoals de inserter die een belangrijke manier bieden om met blokken en patronen te werken.</p>\n</div>\n</div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-db69df54 wp-block-columns-is-layout-flex\" style=\"margin-top:var(--wp--preset--spacing--50);margin-bottom:var(--wp--preset--spacing--50)\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:50%\">\n<h3 class=\"wp-block-heading\">En nog veel meer</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Voor een uitgebreid overzicht van alle nieuwe functies en verbeteringen in WordPress 6.6, bezoek de feature-showcase site.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-vertically-aligned-center is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:50%\">\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"https://wordpress.org/download/releases/6-6/\">Bekijk alles wat nieuw is</a></div>\n</div>\n</div>\n</div>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" style=\"margin-top:var(--wp--preset--spacing--50);margin-bottom:var(--wp--preset--spacing--50)\" />\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-db69df54 wp-block-columns-is-layout-flex\" style=\"margin-top:var(--wp--preset--spacing--50);margin-bottom:var(--wp--preset--spacing--50)\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:33.33%\">\n<figure class=\"wp-block-image size-full\"><a href=\"https://nl.wordpress.org/files/2024/07/image-4.png\"><img loading=\"lazy\" decoding=\"async\" width=\"280\" height=\"280\" src=\"https://nl.wordpress.org/files/2024/07/image-4.png\" alt=\"\" class=\"wp-image-1384\" srcset=\"https://nl.wordpress.org/files/2024/07/image-4.png 280w, https://nl.wordpress.org/files/2024/07/image-4-150x150.png 150w\" sizes=\"auto, (max-width: 280px) 100vw, 280px\" /></a></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:66.66%\">\n<h3 class=\"wp-block-heading\">Meer leren over WordPress 6.6</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://learn.wordpress.org/\">Learn WordPress</a>&nbsp;is een gratis bron voor nieuwe en ervaren WordPress gebruikers. Learn staat vol met how-to video&#8217;s over het gebruik van verschillende functies in WordPress,&nbsp;<a href=\"https://learn.wordpress.org/online-workshops/\">interactieve workshops</a>&nbsp;om dieper op onderwerpen in te gaan, en lesplannen om diep in te gaan op specifieke gebieden van WordPress.</p>\n</div>\n</div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-db69df54 wp-block-columns-is-layout-flex\" style=\"margin-top:var(--wp--preset--spacing--50);margin-bottom:var(--wp--preset--spacing--50)\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"wp-block-paragraph\">Verken de <a href=\"https://make.wordpress.org/core/wordpress-6-6-field-guide/\">WordPress 6.6 Field Guide</a>. Leer over de veranderingen in deze release met gedetailleerde ontwikkelaars notities om je te helpen bouwen met WordPress.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/documentation/wordpress-version/version-6-6/\">Lees de WordPress 6.6 release notes</a> voor informatie over installatie, verbeteringen, opgeloste problemen, bijdragers aan de release, leermiddelen en de lijst met bestandswijzigingen.</p>\n</div>\n</div>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"https://nl.wordpress.org/2024/07/17/wordpress-6-6-dorsey-is-beschikbaar/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1377\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"WordPress 6.5 “Regina” is vrijgegeven\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:72:\"https://nl.wordpress.org/2024/04/02/wordpress-6-5-regina-is-vrijgegeven/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"https://nl.wordpress.org/2024/04/02/wordpress-6-5-regina-is-vrijgegeven/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 02 Apr 2024 21:11:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"Release\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://nl.wordpress.org/?p=1353\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:394:\"Breid je site-creatie ervaring uit met WordPress 6.5. Verken meer mogelijkheden om het helemaal van jou te maken, met nieuwe functies en verbeteringen die je creatieve werk verfijnen. Ontdek de nieuwste toevoegingen aan de ontwikkelaars ervaring, met frisse fundamentele gereedschappen die klaarstaan om de toekomst van blokken te transformeren. Lettertypen toevoegen en beheren op je [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Remkus de Vries\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:12445:\"\n<figure class=\"wp-block-image size-large\"><a href=\"https://nl.wordpress.org/files/2024/04/image-9.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://nl.wordpress.org/files/2024/04/image-9-1024x683.png\" alt=\"\" class=\"wp-image-1368\" srcset=\"https://nl.wordpress.org/files/2024/04/image-9-1024x683.png 1024w, https://nl.wordpress.org/files/2024/04/image-9-300x200.png 300w, https://nl.wordpress.org/files/2024/04/image-9-768x512.png 768w, https://nl.wordpress.org/files/2024/04/image-9-1536x1024.png 1536w, https://nl.wordpress.org/files/2024/04/image-9.png 2048w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Breid je site-creatie ervaring uit met WordPress 6.5. Verken meer mogelijkheden om het helemaal van jou te maken, met nieuwe functies en verbeteringen die je creatieve werk verfijnen. Ontdek de nieuwste toevoegingen aan de ontwikkelaars ervaring, met frisse fundamentele gereedschappen die klaarstaan om de toekomst van blokken te transformeren.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://nl.wordpress.org/files/2024/04/image.png\"><img loading=\"lazy\" decoding=\"async\" width=\"872\" height=\"872\" src=\"https://nl.wordpress.org/files/2024/04/image.png\" alt=\"\" class=\"wp-image-1354\" srcset=\"https://nl.wordpress.org/files/2024/04/image.png 872w, https://nl.wordpress.org/files/2024/04/image-300x300.png 300w, https://nl.wordpress.org/files/2024/04/image-150x150.png 150w, https://nl.wordpress.org/files/2024/04/image-768x768.png 768w\" sizes=\"auto, (max-width: 872px) 100vw, 872px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Lettertypen toevoegen en beheren op je site</h3>\n\n\n\n<p class=\"wp-block-paragraph\">De nieuwe lettertypebibliotheek geeft je controle over een essentieel onderdeel van het ontwerp van je site &#8211; typografie &#8211; zonder codering of extra stappen. Installeer, verwijder en activeer moeiteloos lokale en Google Fonts op je site voor elk blokthema. De mogelijkheid om aangepaste typografie collecties op te nemen, geeft site makers en uitgevers nog meer keuze.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://nl.wordpress.org/files/2024/04/image-1.png\"><img loading=\"lazy\" decoding=\"async\" width=\"872\" height=\"872\" src=\"https://nl.wordpress.org/files/2024/04/image-1.png\" alt=\"\" class=\"wp-image-1356\" srcset=\"https://nl.wordpress.org/files/2024/04/image-1.png 872w, https://nl.wordpress.org/files/2024/04/image-1-300x300.png 300w, https://nl.wordpress.org/files/2024/04/image-1-150x150.png 150w, https://nl.wordpress.org/files/2024/04/image-1-768x768.png 768w\" sizes=\"auto, (max-width: 872px) 100vw, 872px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Ontvang meer details van je stijlrevisies.</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Werk aan creatieve projecten met een meer omvattend beeld van wat er is gedaan &#8211; en waar je op terug kunt vallen. Krijg details zoals tijdstempels, korte samenvattingen en een gepagineerde lijst van totale revisies. Bekijk revisies vanuit de stijlgids om wijzigingen te zien buiten wat je aan het doen bent. Revisies zijn nu ook beschikbaar voor templates en template onderdelen.</p>\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-1 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-medium\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"300\" data-id=\"1359\" src=\"https://nl.wordpress.org/files/2024/04/image-3-300x300.png\" alt=\"\" class=\"wp-image-1359\" srcset=\"https://nl.wordpress.org/files/2024/04/image-3-300x300.png 300w, https://nl.wordpress.org/files/2024/04/image-3-150x150.png 150w, https://nl.wordpress.org/files/2024/04/image-3.png 560w\" sizes=\"auto, (max-width: 300px) 100vw, 300px\" /></figure>\n\n\n\n<figure class=\"wp-block-image size-medium\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"300\" data-id=\"1360\" src=\"https://nl.wordpress.org/files/2024/04/image-4-300x300.png\" alt=\"\" class=\"wp-image-1360\" srcset=\"https://nl.wordpress.org/files/2024/04/image-4-300x300.png 300w, https://nl.wordpress.org/files/2024/04/image-4-150x150.png 150w, https://nl.wordpress.org/files/2024/04/image-4.png 560w\" sizes=\"auto, (max-width: 300px) 100vw, 300px\" /></figure>\n\n\n\n<figure class=\"wp-block-image size-medium\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"300\" data-id=\"1361\" src=\"https://nl.wordpress.org/files/2024/04/image-5-300x300.png\" alt=\"\" class=\"wp-image-1361\" srcset=\"https://nl.wordpress.org/files/2024/04/image-5-300x300.png 300w, https://nl.wordpress.org/files/2024/04/image-5-150x150.png 150w, https://nl.wordpress.org/files/2024/04/image-5.png 560w\" sizes=\"auto, (max-width: 300px) 100vw, 300px\" /></figure>\n\n\n\n<figure class=\"wp-block-image size-medium\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"300\" data-id=\"1363\" src=\"https://nl.wordpress.org/files/2024/04/image-7-300x300.png\" alt=\"\" class=\"wp-image-1363\" srcset=\"https://nl.wordpress.org/files/2024/04/image-7-300x300.png 300w, https://nl.wordpress.org/files/2024/04/image-7-150x150.png 150w, https://nl.wordpress.org/files/2024/04/image-7.png 560w\" sizes=\"auto, (max-width: 300px) 100vw, 300px\" /></figure>\n\n\n\n<figure class=\"wp-block-image size-medium\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"300\" data-id=\"1364\" src=\"https://nl.wordpress.org/files/2024/04/image-8-300x300.png\" alt=\"\" class=\"wp-image-1364\" srcset=\"https://nl.wordpress.org/files/2024/04/image-8-300x300.png 300w, https://nl.wordpress.org/files/2024/04/image-8-150x150.png 150w, https://nl.wordpress.org/files/2024/04/image-8.png 560w\" sizes=\"auto, (max-width: 300px) 100vw, 300px\" /></figure>\n\n\n\n<figure class=\"wp-block-image size-medium\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"300\" data-id=\"1362\" src=\"https://nl.wordpress.org/files/2024/04/image-6-300x300.png\" alt=\"\" class=\"wp-image-1362\" srcset=\"https://nl.wordpress.org/files/2024/04/image-6-300x300.png 300w, https://nl.wordpress.org/files/2024/04/image-6-150x150.png 150w, https://nl.wordpress.org/files/2024/04/image-6.png 560w\" sizes=\"auto, (max-width: 300px) 100vw, 300px\" /></figure>\n</figure>\n\n\n\n<h3 class=\"wp-block-heading\">Doe meer met achtergrondafbeeldingen in groepsblokken</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Beheer grootte, herhaling en brandpunt opties zodat je kunt experimenteren met subtiele of opvallende manieren om visuele interesse toe te voegen aan lay-outs.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Krijg meer controle over afbeeldingen in omslagblokken</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Stel aspect verhoudingen in voor omslagblok afbeeldingen en voeg eenvoudig kleur overlays toe die automatisch de kleur van je gekozen afbeelding gebruiken.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Voeg boxschaduw ondersteuning toe aan nog meer blokken.</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Met ingeschakelde schaduw ondersteuning kun je lay-outs maken met visuele diepte of een beetje persoonlijkheid toevoegen aan je ontwerp.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Ontdek nieuwe gegevensweergaven</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Vind en organiseer je gegevens zoals jij wil met gegevens weergaven voor pagina&#8217;s, templates, patronen en template onderdelen. Schik het in een tabel of raster weergave met de mogelijkheid om velden te wisselen en bulk wijzigingen aan te brengen.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Soepeler verslepen</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Voel het verschil wanneer je dingen verplaatst, met handige visuele aanwijzingen zoals verplaatste items in lijstweergave of moeiteloos slepen naar elke plek in je werkruimte—van begin tot eind.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Verbeterde link besturingen</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Maak en beheer links eenvoudig met een meer intuïtieve link-creatie ervaring, zoals een gestroomlijnde UI en een snelkoppeling voor het kopiëren van links.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Breng interacties naar blokken met de Interactivity API</h3>\n\n\n\n<p class=\"wp-block-paragraph\">De Interactiviteit API biedt ontwikkelaars een gestandaardiseerde methode voor het bouwen van interactieve front-end ervaringen met blokken. Het vereenvoudigt het proces, met minder afhankelijkheid van externe tools, terwijl het optimale prestaties behoudt. Gebruik het om gedenkwaardige gebruikerservaringen te creëren, zoals het direct ophalen van zoekresultaten of door bezoekers direct interactie te hebben over de inhoud in realtime.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Verbind blokken met aangepaste velden of andere dynamische inhoud</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Link core blokattributen aan aangepaste velden en gebruik de waarde van aangepaste velden zonder aangepaste blokken te creëren. Aangedreven door de Block Bindings API, kunnen ontwikkelaars deze mogelijkheid verder uitbreiden om blokken te verbinden met elke dynamische inhoud—zelfs voorbij aangepaste velden. Als er gegevens elders zijn opgeslagen, wijs blokken dan eenvoudig naar die nieuwe bron met slechts een paar regels code.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Weergave gereedschap toevoegen aan klassieke thema&#8217;s.</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Geef ontwerpers en makers die klassieke thema&#8217;s gebruiken toegang tot een verbeterde ontwerp ervaring. Kies voor ondersteuning voor afstand, rand, typografie en kleurenopties, zelfs zonder het gebruik van theme.json. Zodra de ondersteuning is ingeschakeld, wordt er automatisch meer gereedschap toegevoegd zodra dat beschikbaar komt.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Verbeteringen aan de plugin ervaring verkennen</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Er is nu een makkelijke manier om afhankelijkheden van plugins te beheren. Auteurs van plugins kunnen een nieuwe&nbsp;<code>Requires Plugins</code>&nbsp;header leveren middels een door komma&#8217;s gescheiden lijst van vereiste plugin slugs, waarmee gebruikers links krijgen om die plugins eerst te installeren en te activeren.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Prestatie updates</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Deze release bevat meer dan 110 prestatie-updates, met een indrukwekkende toename in snelheid en efficiëntie in zowel de bericht-editor als de Site-editor. Het laden is meer dan twee keer sneller dan in 6.4, met een verwerkingssnelheid van invoer tot wel vijf keer sneller dan de vorige release. Vertaalde sites zien tot wel 25% verbetering in laadtijd voor deze release.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Toegankelijkheid verbeteringen</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Deze release bevat meer dan 65 toegankelijkheidsverbeteringen over het hele platform, waardoor het toegankelijker is dan ooit. Deze release voegt oplossingen toe voor contrastinstellingen, cursor focus, submenu&#8217;s en de positionering van elementen, onder vele anderen, die helpen de WordPress ervaring voor iedereen te verbeteren.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Meer leren over WordPress 6.5</h3>\n\n\n\n<figure class=\"wp-block-image alignleft size-full\"><a href=\"https://nl.wordpress.org/files/2024/04/image-2.png\"><img loading=\"lazy\" decoding=\"async\" width=\"280\" height=\"280\" src=\"https://nl.wordpress.org/files/2024/04/image-2.png\" alt=\"\" class=\"wp-image-1358\" srcset=\"https://nl.wordpress.org/files/2024/04/image-2.png 280w, https://nl.wordpress.org/files/2024/04/image-2-150x150.png 150w\" sizes=\"auto, (max-width: 280px) 100vw, 280px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://learn.wordpress.org/\">Learn WordPress</a>&nbsp;is een gratis bron voor nieuwe en ervaren WordPress gebruikers. Learn staat vol met how-to video&#8217;s over het gebruik van verschillende functies in WordPress,&nbsp;<a href=\"https://learn.wordpress.org/online-workshops/\">interactieve workshops</a>&nbsp;om dieper op onderwerpen in te gaan, en lesplannen om diep in te gaan op specifieke gebieden van WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Verken de&nbsp;<a href=\"https://make.wordpress.org/core/wordpress-6-5-field-guide/\">WordPress 6.5 Field Guide</a>. Leer over de veranderingen in deze release met gedetailleerde ontwikkelaars notities om je te helpen bouwen met WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/documentation/wordpress-version/version-6-5/\">Lees de WordPress 6.5 release notes</a>&nbsp;voor informatie over installatie, verbeteringen, opgeloste problemen, bijdragers aan de release, leermiddelen en de lijst met bestandswijzigingen.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"https://nl.wordpress.org/2024/04/02/wordpress-6-5-regina-is-vrijgegeven/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1353\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"Community Voices –  De Nederlandse WordPress Community\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"https://nl.wordpress.org/2023/11/17/community-voices-de-nederlandse-wordpress-community/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:96:\"https://nl.wordpress.org/2023/11/17/community-voices-de-nederlandse-wordpress-community/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 17 Nov 2023 16:09:44 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Algemeen\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://nl.wordpress.org/?p=1310\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:376:\"Een aantal Nederlandse WordPress Communityleden werden onlangs uitgenodigd door Bob Dunn van de Do the Woo podcast voor een editie van zijn Community Voices, WordPress Around the World podcast. Doel is het in de schijnwerpers zetten van de Nederlandse WordPress community. Ga mee met&#160;Ita Pronk, Luc Princen, Marcel Bootsman, Marieke van de Rakt, Roan de Vries, [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Remkus de Vries\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:1579:\"\n<p class=\"wp-block-paragraph\">Een aantal Nederlandse WordPress Communityleden werden onlangs uitgenodigd door Bob Dunn van de Do the Woo podcast voor een editie van zijn Community Voices, WordPress Around the World podcast. Doel is het in de schijnwerpers zetten van de Nederlandse WordPress community.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">Ga mee met&nbsp;<strong>Ita Pronk, Luc Princen, Marcel Bootsman, Marieke van de Rakt, Roan de Vries, Taco Verdonschot en Wendie Huis in &#8217;t Veld, leden van de Nederlandse WordPress community</strong>, terwijl ze een gesprek voeren over hun ervaringen met WordPress en de voordelen van het deel uitmaken van de community.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Ze bespreken het bijwonen van WordCamps, conferenties die over de hele wereld worden gehouden voor WordPress gebruikers, en de waarde van netwerken en leren van anderen in de gemeenschap. Ze bespreken ook het belang van het bijdragen aan de gemeenschap, hetzij door vrijwilligerswerk, spreken op evenementen of het delen van kennis en expertise.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Iedereen in de show moedigt iedereen die geïnteresseerd is in WordPress aan om betrokken te raken bij de community, evenementen bij te wonen en gebruik te maken van de beschikbare bronnen en ondersteuning.</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">Je kunt de <a href=\"https://dothewoo.io/de-nederlandse-wordpress-community-the-dutch-wordpress-community/\">podcast aflevering hier beluisteren</a>.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:93:\"https://nl.wordpress.org/2023/11/17/community-voices-de-nederlandse-wordpress-community/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1310\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:42:\"WordPress 6.4 “Shirley” is vrijgegeven\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"https://nl.wordpress.org/2023/11/07/wordpress-6-4-shirley-is-vrijgegeven/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:81:\"https://nl.wordpress.org/2023/11/07/wordpress-6-4-shirley-is-vrijgegeven/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 07 Nov 2023 22:23:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"Release\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://nl.wordpress.org/?p=1301\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:367:\"Elke versie van WordPress geeft je creatieve vrijheid, en WordPress 6.4 is niet anders. Nieuwe functies en upgrades voor het bewerken, ontwerpen en schrijven van je site zorgen ervoor dat je ideeën naadloos vorm kunnen krijgen. Verhoog je site ontwikkelingsreis met de flexibiliteit en kracht van WordPress 6.4. Zeg hallo tegen Twenty Twenty-Four Ervaar de [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Remkus de Vries\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:8598:\"\n<p class=\"wp-block-paragraph\">Elke versie van WordPress geeft je creatieve vrijheid, en WordPress 6.4 is niet anders. Nieuwe functies en upgrades voor het bewerken, ontwerpen en schrijven van je site zorgen ervoor dat je ideeën naadloos vorm kunnen krijgen. Verhoog je site ontwikkelingsreis met de flexibiliteit en kracht van WordPress 6.4.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://nl.wordpress.org/files/2023/11/image-1.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://nl.wordpress.org/files/2023/11/image-1-1024x683.png\" alt=\"\" class=\"wp-image-1306\" srcset=\"https://nl.wordpress.org/files/2023/11/image-1-1024x683.png 1024w, https://nl.wordpress.org/files/2023/11/image-1-300x200.png 300w, https://nl.wordpress.org/files/2023/11/image-1-768x512.png 768w, https://nl.wordpress.org/files/2023/11/image-1-1536x1024.png 1536w, https://nl.wordpress.org/files/2023/11/image-1.png 2048w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Zeg hallo tegen Twenty Twenty-Four</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Ervaar de nieuwste ontwikkelingen in het bewerken van sites met&nbsp;<a href=\"https://make.wordpress.org/core/2023/08/24/introducing-twenty-twenty-four/\">Twenty Twenty-Four</a>. Gebouwd met drie verschillende gebruiksscenarios in gedachten, maakt de veelzijdigheid van het nieuwe standaard thema het een ideale keuze voor bijna elk type site. Duik in de verzameling templates en patronen en ontgrendel een wereld van creatieve mogelijkheden met slechts een paar aanpassingen.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://nl.wordpress.org/files/2023/11/image.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"759\" src=\"https://nl.wordpress.org/files/2023/11/image-1024x759.png\" alt=\"\" class=\"wp-image-1303\" srcset=\"https://nl.wordpress.org/files/2023/11/image-1024x759.png 1024w, https://nl.wordpress.org/files/2023/11/image-300x223.png 300w, https://nl.wordpress.org/files/2023/11/image-768x570.png 768w, https://nl.wordpress.org/files/2023/11/image.png 1200w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Een lightbox effect aan afbeeldingen toevoegen</h3>\n\n\n\n<p class=\"wp-block-paragraph\">De lightbox functionaliteit inschakelen voor interactieve, schermvullende afbeeldingen met een simpele klik. Pas het globaal toe of op specifieke afbeeldingen om de kijkervaring aan te passen.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Patronen categoriseren en filteren</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Organiseer je gesynchroniseerde en niet-gesynchroniseerde patronen met categorieën. Verken geavanceerde filtering in de patronensectie van de invoegtoepassing om ze allemaal intuïtiever te vinden.</p>\n</div>\n</div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Krijg meer gedaan met het commandopalet</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Geniet van&nbsp;<a href=\"https://make.wordpress.org/core/2023/09/12/core-editor-improvement-commanding-the-command-palette/\">een vernieuwd ontwerp en meer opdrachten</a>&nbsp;om te vinden wat je zoekt, taken efficiënt uit te voeren en tijd te besparen terwijl je creëert.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Groepblokken hernoemen</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Stel aangepaste namen in voor groepsblokken om delen van je inhoud gemakkelijk te organiseren en te onderscheiden. Deze namen zijn zichtbaar in de lijstweergave.</p>\n</div>\n</div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Afbeelding voorbeelden in lijst weergave</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Nieuwe media voorbeelden voor galerij en afbeelding blokken in lijstweergave laten je in één oogopslag zien waar afbeeldingen in je inhoud zich bevinden en hoe ze eruit zien.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Deel patronen over sites</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Moet je je aangepaste patronen op een andere site gebruiken? Het is simpel! Importeer en exporteer ze als JSON bestanden vanuit de patronen weergave van de Site-editor.</p>\n</div>\n</div>\n\n\n\n<h3 class=\"wp-block-heading\">Geniet van nieuwe schrijfverbeteringen</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/core/2023/10/05/core-editor-improvement-ensuring-excellence-in-the-writing-experience/\">Nieuwe verbeteringen</a>&nbsp;zorgen ervoor dat je contentcreatie reis soepel verloopt. Vind nieuwe sneltoetsen in lijstweergave, verfijnde lijst samenvoeging en verbeterde controle over link instellingen. Een vernieuwde en samenhangende toolbar ervaring voor navigatie, lijst en citaat blokken stelt je in staat om efficiënt te werken met de benodigde gereedschap opties.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Bouw je creatieve visie met meer ontwerp gereedschap</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Word creatief met nieuwe achtergrondafbeeldingen in groepsblokken en zorg voor consistente afmetingen van afbeeldingen met plaatshouder aspectverhoudingen. Wil je knoppen toevoegen aan je navigatieblok? Je kunt het nu gemakkelijk doen zonder aangepaste CSS. Als je werkt met gesynchroniseerde patronen, blijven de uitlijning instellingen behouden voor een naadloze patroon creatie ervaring.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Introductie van blok hooks</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Blok hooks is een nieuwe krachtige functie die plugins in staat stelt om blokken automatisch in te voegen in de inhoud in relatie tot een ander blok. Denk eraan als aanbevelingen om je werk met blokken intuïtiever te maken. Een nieuw &#8220;Plugins&#8221; paneel geeft je volledige controle om ze aan je behoeften aan te passen &#8211; blokken toevoegen, negeren en herschikken zoals gewenst.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Performance</h3>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.4 bevat meer dan 100 performance updates voor een snellere en efficiëntere ervaring. Verbeteringen richten zich op de prestaties van het laden van templates voor blok thema&#8217;s en klassieke thema&#8217;s, het gebruik van de script laad strategieën &#8220;defer&#8221; en &#8220;async&#8221; in de core, blokken en thema&#8217;s, en optimalisatie van automatisch geladen opties.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Toegankelijkheid</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Elke release is toegewijd om WordPress toegankelijk te maken voor iedereen. 6.4 brengt verbeteringen aan in de lijstweergave en ondersteuning voor aria-label voor het navigatieblok, naast andere hoogtepunten. De beheerder gebruikersinterface (UI) bevat verbeteringen in de plaatsing van knoppen, context van &#8220;Toevoegen&#8221; menu-items en gesproken berichten voor de site diagnose.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Meer leren over WordPress 6.4</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://learn.wordpress.org/\">Learn WordPress</a>&nbsp;is een gratis bron voor nieuwe en ervaren WordPress gebruikers. Learn staat vol met how-to video&#8217;s over het gebruik van verschillende functies in WordPress,&nbsp;<a href=\"https://learn.wordpress.org/online-workshops/\">interactieve workshops</a>&nbsp;om dieper op onderwerpen in te gaan, en lesplannen om diep in te gaan op specifieke gebieden van WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Verken de&nbsp;<a href=\"https://make.wordpress.org/core/2023/10/23/wordpress-6-4-field-guide/\">WordPress 6.4 Field Guide</a>. Leer over de veranderingen in deze release met gedetailleerde ontwikkelaars notities om je te helpen bouwen met WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/documentation/wordpress-version/version-6-4/\">Lees de WordPress 6.4 release notes</a>&nbsp;voor informatie over installatie, verbeteringen, opgeloste problemen, bijdragers aan de release, leermiddelen en de lijst met bestandswijzigingen.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:78:\"https://nl.wordpress.org/2023/11/07/wordpress-6-4-shirley-is-vrijgegeven/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1301\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"WordPress 6.3 “Lionel” is vrijgegeven\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:72:\"https://nl.wordpress.org/2023/08/08/wordpress-6-3-lionel-is-vrijgegeven/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:81:\"https://nl.wordpress.org/2023/08/08/wordpress-6-3-lionel-is-vrijgegeven/#comments\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 08 Aug 2023 20:08:11 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"Release\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://nl.wordpress.org/?p=1278\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:345:\"Maak op efficiëntere wijze prachtige en overtuigende websites dan ooit tevoren. Of je nu een volledige site wil bouwen zonder codering of een ontwikkelaar bent die elk detail wil aanpassen, WordPress 6.3 heeft iets voor je. Doe alles in de Site-editor WordPress 6.3 brengt je inhoud, templates en patronen voor de eerste keer samen in [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Remkus de Vries\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:8056:\"\n<p class=\"wp-block-paragraph\">Maak op efficiëntere wijze prachtige en overtuigende websites dan ooit tevoren. Of je nu een volledige site wil bouwen zonder codering of een ontwikkelaar bent die elk detail wil aanpassen, WordPress 6.3 heeft iets voor je.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Doe alles in de Site-editor</h3>\n\n\n\n<figure class=\"wp-block-image alignright size-full is-resized\"><a href=\"https://nl.wordpress.org/files/2023/08/image.png\"><img loading=\"lazy\" decoding=\"async\" src=\"https://nl.wordpress.org/files/2023/08/image.png\" alt=\"\" class=\"wp-image-1279\" style=\"object-fit:cover;width:333px;height:333px\" width=\"333\" height=\"333\" srcset=\"https://nl.wordpress.org/files/2023/08/image.png 872w, https://nl.wordpress.org/files/2023/08/image-300x300.png 300w, https://nl.wordpress.org/files/2023/08/image-150x150.png 150w, https://nl.wordpress.org/files/2023/08/image-768x768.png 768w\" sizes=\"auto, (max-width: 333px) 100vw, 333px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.3 brengt je inhoud, templates en patronen voor de eerste keer samen in de Site-editor. Voeg pagina&#8217;s toe, bekijk stijlvariaties, maak gesynchroniseerde patronen en geniet van nauwkeurige controle over je navigatiemenu&#8217;s. Geen tijd meer verspild aan het schakelen tussen verschillende ruimtes op je site &#8211; nu kun je je focussen op wat het belangrijkst is. Van creatie tot voltooiing, alles op één plek.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Maak patronen aan en synchroniseer ze</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Rangschik blokken op onbeperkte manieren en sla ze op als patronen voor gebruik op je site. Je kunt zelfs aangeven of je patronen wilt synchroniseren (voorheen bekend als &#8220;herbruikbare blokken&#8221;) zodat één wijziging van toepassing is op alle delen van je site. Of gebruik patronen als startpunt met de mogelijkheid om elke instantie aan te passen.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://nl.wordpress.org/files/2023/08/image-1.png\"><img loading=\"lazy\" decoding=\"async\" width=\"872\" height=\"872\" src=\"https://nl.wordpress.org/files/2023/08/image-1.png\" alt=\"\" class=\"wp-image-1280\" srcset=\"https://nl.wordpress.org/files/2023/08/image-1.png 872w, https://nl.wordpress.org/files/2023/08/image-1-300x300.png 300w, https://nl.wordpress.org/files/2023/08/image-1-150x150.png 150w, https://nl.wordpress.org/files/2023/08/image-1-768x768.png 768w\" sizes=\"auto, (max-width: 872px) 100vw, 872px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Werk sneller met het commando palet</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Schakel over naar een specifiek template of open je editor voorkeuren met een nieuwe tool die je helpt om snel door uitgebreide functionaliteit te navigeren. Met eenvoudige sneltoetsen (⌘+k op Mac of ctrl+k op Windows), door te klikken op het zoekpictogram in de zijbalk in de site weergave, of door te klikken op de titelbalk, kom je in enkele seconden waar je moet zijn en kun je doen wat je moet doen.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Scherp je ontwerpen aan met nieuwe gereedschappen</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Nieuwe ontwerpbesturingen bieden meer veelzijdigheid voor het nauwkeurig afstemmen van ontwerpen, te beginnen met de mogelijkheid om de stijlen van je bijschrift aan te passen vanuit de Stijl interface zonder codering. Je kunt je duotoon filters beheren in Stijlen voor ondersteunde blokken en kiezen uit de opties die je thema biedt of ze volledig uitschakelen. Het Omslagblok krijgt extra instellingen voor tekstkleur, lay-out besturing en randopties, waardoor dit krachtige blok nog handiger wordt.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Volg ontwerpwijzigingen op met stijl revisies</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Je kunt nu zien hoe je site eruitzag op een specifiek moment. Visualiseer deze revisies in een tijdlijn en krijg toegang tot een optie met één klik om eerdere stijlen terug te zetten.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Annoteer met het blok Voetnoten</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Voetnoten voegen handige annotaties toe aan je inhoud. Nu kun je voetnoten toevoegen en koppelen aan elke paragraaf.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Toon of verberg inhoud met het Details blok</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Gebruik het blok om een verrassing niet te bederven, een interactieve vraag- en antwoordsectie te maken, of een lange paragraaf te verbergen onder een koptekst.</p>\n\n\n\n<h3 class=\"wp-block-heading\">De performance krijgt een boost</h3>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.3 heeft meer dan 170 performance updates, waaronder uitstellen en asynchroon ondersteuning voor de Scripts API en ondersteuning voor fetchpriority voor afbeeldingen. Deze verbeteringen kunnen de laadtijd van je website verbeteren zoals waargenomen door bezoekers, samen met blok template resolutie, afbeeldingen die later worden geladen en de emoji lader.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Toegankelijkheid blijft een core focus</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Met meer dan 50 toegankelijkheidsverbeteringen in het hele platform is WordPress 6.3 nog toegankelijker dan ooit tevoren. Verbeterde labeling, geoptimaliseerde tab- en pijltoetsnavigatie, herziene hiërarchie van kopteksten en nieuwe bedieningselementen in de afbeeldingbewerker van de beheerder stellen gebruikers van ondersteunende technologieën in staat om gemakkelijker te navigeren.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Bekijk blokthema&#8217;s</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Ervaar blokthema&#8217;s voordat je overschakelt en bekijk de Site-editor, met opties om direct aanpassingen te maken voordat je je committeert aan een nieuw thema.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Stel de beeldverhouding in op afbeeldingen</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Specificeer je afbeeldingverhoudingen en zorg voor ontwerpkwaliteit, vooral bij het gebruik van afbeeldingen in patronen.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Bouw je site zonder afleiding</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Afleidingsvrij ontwerpen is nu beschikbaar in de Site-editor.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Herontdek de bovenste toolbar</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Een vernieuwde bovenste toolbar biedt hoofd selectoren voor geneste blokken, opties bij het selecteren van meerdere blokken, en een nieuwe interface die is ingebed in de titelbalk met nieuwe functionaliteit in gedachten.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Verbeteringen voor de lijstweergave</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Verslepen op elke inhoudslaag en verwijder elk blok dat je wil in de geüpdatete lijstweergave.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Bouw templates met patronen</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Maak unieke patronen om het maken van templates een vliegende start te geven met een nieuwe modus die toegang biedt tot het selecteren van patronen.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Meer leren over WordPress 6.3</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://learn.wordpress.org/\">Leer WordPress</a> is een gratis documentatiecentrum voor nieuwe en ervaren WordPress gebruikers. Leer is gevuld met instructievideo&#8217;s over het gebruik van verschillende functies in WordPress, <a href=\"https://learn.wordpress.org/online-workshops/\">interactieve evenementen</a> om onderwerpen grondig te verkennen, en lesplannen om diep in te gaan op specifieke gebieden van WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">De laatste versie van de&nbsp;<a href=\"https://make.wordpress.org/core/2023/07/18/wordpress-6-3-field-guide/\">WordPress field guide</a>&nbsp;bekijken. Het staat vol met gedetailleerde ontwikkelaars notities om je te helpen bouwen met WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/documentation/wordpress-version/version-6-3/\">Lees de WordPress 6.3 release notes</a>&nbsp;voor meer informatie over de opgenomen verbeteringen en opgeloste problemen, installatie-informatie, reacties en bronnen van ontwikkelaars, medewerkers aan de release en de lijst met bestandswijzigingen in deze release.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"https://nl.wordpress.org/2023/08/08/wordpress-6-3-lionel-is-vrijgegeven/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1278\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"WordPress 6.2 “Dolphy” is vrijgegeven\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:72:\"https://nl.wordpress.org/2023/03/29/wordpress-6-2-dolphy-is-vrijgegeven/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"https://nl.wordpress.org/2023/03/29/wordpress-6-2-dolphy-is-vrijgegeven/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 29 Mar 2023 21:23:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"Release\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://nl.wordpress.org/?p=1240\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:377:\"WordPress 6.2 bevat meer dan 292 verbeteringen en 394 bugfixes. Deze pagina belicht de nieuwste functies sinds de release van WordPress 6.1 in november 2022. Van korte updates tot hulpmiddelen voor ontwikkelaars, er valt veel te ontdekken. Verken en bewerk je site vanuit de Site-ditor Een geüpdatete interface geeft je meer controle over je site-bewerkingservaring. [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Remkus de Vries\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5874:\"\n<figure class=\"wp-block-image size-large\"><a href=\"https://nl.wordpress.org/files/2023/05/image.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://nl.wordpress.org/files/2023/05/image-1024x683.png\" alt=\"\" class=\"wp-image-1241\" srcset=\"https://nl.wordpress.org/files/2023/05/image-1024x683.png 1024w, https://nl.wordpress.org/files/2023/05/image-300x200.png 300w, https://nl.wordpress.org/files/2023/05/image-768x512.png 768w, https://nl.wordpress.org/files/2023/05/image-1536x1024.png 1536w, https://nl.wordpress.org/files/2023/05/image.png 2048w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.2 bevat meer dan 292 verbeteringen en 394 bugfixes. Deze pagina belicht de nieuwste functies sinds de release van WordPress 6.1 in november 2022. Van korte updates tot hulpmiddelen voor ontwikkelaars, er valt veel te ontdekken.</p>\n\n\n\n<span id=\"more-1240\"></span>\n\n\n\n<h3 class=\"wp-block-heading\">Verken en bewerk je site vanuit de Site-ditor</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Een geüpdatete interface geeft je meer controle over je site-bewerkingservaring. Blader door volledige voorvertoningen van je templates en templateonderdelen en begin met het bewerken van je site waar je maar wilt.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Beheer je menu op meer manieren met het navigatieblok</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Een nieuwe zijbalkervaring maakt het gemakkelijker om je sitenavigatie te bewerken. Je kunt sneller menu-items toevoegen, verwijderen en opnieuw ordenen, hoe complex je menu&#8217;s ook zijn.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Ontdek een soepelere ervaring voor de blok-inserter</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Een vernieuwd ontwerp geeft je meer zichtbaarheid en gemakkelijker toegang tot de inhoud die je nodig hebt. Gebruik de tab Media om snel inhoud uit je bestaande mediabibliotheek te slepen en neer te zetten. Vind sneller patronen met een gesplitste weergave waarmee je door categorieën kunt navigeren en voorbeelden in één keer kunt bekijken.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Vind de besturingselementen die je nodig hebt wanneer je ze nodig hebt</h3>\n\n\n\n<p class=\"wp-block-paragraph\">De zijbalk van je blok instellingen is beter georganiseerd met tabs voor instellingen en stijlen. Dus de gereedschappen die je nodig hebt, zijn gemakkelijk te identificeren en toegankelijk.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Bouw sneller met headers en footers voor blokthema&#8217;s</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Ontdek een nieuwe verzameling header en footer patronen om uit te kiezen. Gebruik ze met elk blokthema als een snel startpunt van hoge kwaliteit voor je sitetemplates.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Verken Openverse media rechtstreeks vanuit de editor</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Openverse bibliotheek catalogiseert meer dan 600 miljoen gratis, openlijk gelicenseerde stock afbeeldingen en audio &#8211; en is nu rechtstreeks geïntegreerd in de editor.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Concentreer je op schrijven met de afleidingsvrije modus</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Voor die keren dat je alleen wil zijn met je ideeën. Je kunt nu al je panelen en bedieningselementen verbergen, zodat je vrij bent om je inhoud tot leven te brengen.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Ervaar de Site-editor, nu uit bèta</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Stabiel en klaar om verder te verkennen: 6.2 is je persoonlijke uitnodiging om te ontdekken wat de volgende generatie WordPress en blok thema&#8217;s kan doen.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Stijlboek</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Gebruik het nieuwe Style Book om een compleet overzicht te krijgen van hoe elk blok in je sitebibliotheek eruitziet. Alles op één plek, alles in één oogopslag.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Kopieer en plak stijlen</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Perfectioneer het ontwerp op één type blok en kopieer en plak die stijlen vervolgens in andere blokken om precies de look te krijgen die je wilt.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Aangepaste CSS</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Start met je site zoals je dat wilt. Voeg CSS toe aan je site, of je blokken, voor nog meer controle over de look en feel van je site.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Sticky positionering</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Kies ervoor om bepaalde blokken vast te zetten aan de bovenkant van een pagina terwijl bezoekers scrollen.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Widgets aan het importeren</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Opties om je favoriete widgets te importeren van klassieke thema&#8217;s naar blokthema&#8217;s.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Lokale lettertypen in thema&#8217;s</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Standaard WordPress thema&#8217;s bieden betere privacy met Google Fonts inbegrepen.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Meer leren over WordPress 6.2</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Ontdek&nbsp;<a href=\"https://learn.wordpress.org/\">learn.wordpress.org</a>&nbsp;voor tutorial video&#8217;s, online workshops, cursussen en lesplannen voor Meetup organisatoren, inclusief nieuwe functies in WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">De laatste versie van de&nbsp;<a href=\"https://make.wordpress.org/core/2023/03/09/wordpress-6-2-field-guide/\">WordPress field guide</a>&nbsp;bekijken. Het staat vol met gedetailleerde ontwikkelaars notities om je te helpen bouwen met WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/support/wordpress-version/version-6-2/\">Lees de WordPress 6.2 release notes</a>&nbsp;voor meer informatie over de opgenomen verbeteringen en opgeloste problemen, installatie-informatie, reacties en bronnen van ontwikkelaars, medewerkers aan de release en de lijst met bestandswijzigingen in deze release.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"https://nl.wordpress.org/2023/03/29/wordpress-6-2-dolphy-is-vrijgegeven/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1240\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:40:\"WordPress 6.1 “Misha” is vrijgegeven\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:71:\"https://nl.wordpress.org/2022/11/01/wordpress-6-1-misha-is-vrijgegeven/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"https://nl.wordpress.org/2022/11/01/wordpress-6-1-misha-is-vrijgegeven/#comments\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 01 Nov 2022 10:11:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"Release\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://nl.wordpress.org/?p=1227\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:378:\"Afgelopen nacht is WordPress 6.1 vrijgegeven. Hier lichten we enkele van de belangrijkste wijzigingen in het product sinds de release van WordPress 6.0 in mei 2022. Je vind er ook bronnen voor ontwikkelaars en iedereen die een dieper inzicht in WordPress wil krijgen. Een nieuw standaardthema met 10 verschillende stijlvariaties Voortbordurend op de basiselementen van [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Remkus de Vries\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:18067:\"\n<p class=\"wp-block-paragraph\">Afgelopen nacht is WordPress 6.1 vrijgegeven. Hier lichten we enkele van de belangrijkste wijzigingen in het product sinds de release van WordPress 6.0 in mei 2022. Je vind er ook bronnen voor ontwikkelaars en iedereen die een dieper inzicht in WordPress wil krijgen.</p>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large\"><img decoding=\"async\" src=\"https://s.w.org/images/core/6.1/about-61-style-variations.webp\" alt=\"\" /></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"has-extra-large-font-size wp-block-paragraph\"><strong>Een nieuw standaardthema met 10 verschillende stijlvariaties</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Voortbordurend op de basiselementen van de 5.9 en 6.0 releases voor blokthema&#8217;s en stijlvariaties, bevat het nieuwe standaardthema, Twenty Twenty-Three, <a href=\"https://make.wordpress.org/design/2022/09/07/tt3-default-theme-announcing-style-variation-selections/\">10 verschillende stijlen</a> en is “ <a href=\"https://make.wordpress.org/themes/handbook/review/accessibility/\">Toegankelijkheidsgereed</a> ”.</p>\n</div>\n</div>\n\n\n\n<span id=\"more-1227\"></span>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"has-extra-large-font-size wp-block-paragraph\"><strong>Een betere ervaring voor makers met verfijnde en aanvullende templates</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/core/2022/07/21/core-editor-improvement-deeper-customization-with-more-template-options/\">Nieuwe templates</a>&nbsp;bevatten een aangepaste template voor berichten en pagina&#8217;s in de site-editor. Tools voor zoeken en vervangen versnellen het ontwerpen van&nbsp;<a href=\"https://make.wordpress.org/core/2022/08/25/core-editor-improvement-refining-the-template-creation-experience/\">template onderdelen</a>.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large\"><img decoding=\"async\" src=\"https://s.w.org/images/core/6.1/about-61-templates.webp\" alt=\"\" /></figure>\n</div>\n</div>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large\"><img decoding=\"async\" src=\"https://s.w.org/images/core/6.1/about-61-design-tools.webp\" alt=\"\" /></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"has-extra-large-font-size wp-block-paragraph\"><strong>Meer consistentie en controle over alle ontwerpgereedschappen</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Upgrades van de&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/11/roster-of-design-tools-per-block/\">bedieningselementen voor ontwerpelementen en blokken</a>&nbsp;maken het proces voor de lay-out en het bouwen van een site consistenter, completer en intuïtiever.</p>\n</div>\n</div>\n\n\n\n<div style=\"height:60px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"has-extra-large-font-size wp-block-paragraph\"><strong>Menu&#8217;s zijn nu eenvoudiger te maken en te beheren</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/core/2022/09/27/navigation-block-fallback-behavior-in-wp-6-1-dev-note/\">Nieuwe fallback opties</a>&nbsp;in het navigatieblok betekenen dat je het geopende menu kunt bewerken; geen zoeken nodig. Bovendien hebben de bedieningselementen voor het kiezen van en werken aan menu&#8217;s hun eigen plaats in de blok instellingen. Het mobiele menusysteem krijgt ook een upgrade met nieuwe functies, waaronder verschillende pictogram opties, om het menu je eigen te maken.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large\"><img decoding=\"async\" src=\"https://s.w.org/images/core/6.1/about-61-navigation.webp\" alt=\"\" /></figure>\n</div>\n</div>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large\"><img decoding=\"async\" src=\"https://s.w.org/images/core/6.1/about-61-document-settings.webp\" alt=\"\" /></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large\"><img decoding=\"async\" src=\"https://s.w.org/images/core/6.1/about-61-lock.webp\" alt=\"\" /></figure>\n</div>\n</div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"has-extra-large-font-size wp-block-paragraph\"><strong>Verbeterde lay-out en visualisatie van documentinstellingen</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Een duidelijkere, beter georganiseerde weergave helpt je om gemakkelijk belangrijke bericht- en pagina-instellingen te bekijken en te beheren, met name de templatekiezer en planner.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"has-extra-large-font-size wp-block-paragraph\"><strong>Vergrendeling instellingen met één klik voor alle binnenblokken</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Wanneer je blokken vergrendelt, kun je met een nieuwe toggle je vergrendeling instellingen toepassen op alle blokken in een bevattend blok, zoals de groep, omslagafbeelding en kolom blokken.</p>\n</div>\n</div>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<h3 class=\"wp-block-heading\">Voeg starter patronen toe aan elk berichttype</h3>\n\n\n\n<p class=\"wp-block-paragraph\">In WordPress 6.0, wanneer je een nieuwe pagina maakte, zag je gesuggereerde patronen zodat je niet hoefde te beginnen met een lege pagina. In 6.1 zal je ook de starter patronen modal zien wanneer je een willekeurig nieuw berichttype maakt.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Sneller blokthema&#8217;s vinden</h3>\n\n\n\n<p class=\"wp-block-paragraph\">De thema&#8217;s directory heeft&nbsp;<a href=\"https://wordpress.org/themes/tags/full-site-editing/\">een filter voor blokthema&#8217;s</a>&nbsp;en een patroon voorbeeld geeft een beter idee van hoe het thema eruit zou kunnen zien tijdens het verkennen van verschillende thema&#8217;s en patronen.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Bewaar je site-editor instellingen voor later</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Site-editor instellingen zijn nu&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/10/changes-to-block-editor-preferences-in-wordpress-6-1/\">permanent voor elke gebruiker</a>. Dit betekent dat je instellingen nu consistent zijn voor alle browsers en apparaten.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Een gestroomlijnd stijlsysteem</h3>\n\n\n\n<p class=\"wp-block-paragraph\">De CSS regels voor marge, padding, typografie, kleuren en randen binnen de&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/10/block-styles-generation-style-engine/\">stijlen engine</a>&nbsp;staan nu allemaal op één plek. Hierdoor besteed je nu minder tijd aan lay-out specifieke taken en het helpt bij het genereren van semantische klasse namen.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Verbeterde toegankelijkheid van beheer en editor</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Meer dan 40 verbeteringen in de toegankelijkheid zoals bijvoorbeeld het oplossen van problemen met focusverlies in de editor, het verbeteren van formulierlabels en hoorbare berichten, eenvoudig alternatieve tekst bewerken, en het repareren van de submenu overlap in de uitgebreide admin navigatie op kleinere schermformaten en hogere zoomniveaus. Leer meer informatie over&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/11/wordpress-6-1-accessibility-improvements/\">toegankelijkheid in WordPress</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Andere interessante opmerkingen</h3>\n\n\n\n<p class=\"wp-block-paragraph\">6.1 bevat een nieuwe time-to-read functie die auteurs de geschatte time-to-read waarden voor pagina&#8217;s, berichten en aangepaste berichttypen laat zien.</p>\n\n\n\n<p class=\"wp-block-paragraph\">De slogan van de site is standaard leeg op nieuwe sites, maar kan worden gewijzigd in&nbsp;Algemene instellingen.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Een nieuw ontwerp voor modals biedt een achtergrond vervagingseffect, waardoor het gemakkelijker wordt om je op de taak te concentreren.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Geüpdatet interface opties en functies</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Updates omvatten&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/10/styling-elements-in-block-themes/\">stijlelementen</a>&nbsp;globaal zoals knoppen, citaten en links; besturen van hoveren, actief en focus statussen voor links met behulp van theme.json (nog niet beschikbaar voor bediening in de interface); en het aanpassen van outline ondersteuning voor blokken en elementen, naast andere functies.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Voortdurende evolutie van lay-out opties</h3>\n\n\n\n<p class=\"wp-block-paragraph\">De standaard dimensies van de content in thema&#8217;s kunnen nu worden overschreven in de stijlen zijbalk, waardoor sitebouwers betere controle hebben over content over de volledige breedte. Ontwikkelaars hebben&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/10/updated-editor-layout-support-in-6-1-after-refactor/\">gedetailleerde controle over deze besturingselementen</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Blok template onderdelen in klassieke thema&#8217;s</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/core/2022/10/04/block-based-template-parts-in-traditional-themes/\">Blok template onderdelen kunnen nu worden gedefinieerd in klassieke thema&#8217;s</a>&nbsp;door de juiste HTML-bestanden toe te voegen aan de&nbsp;<code>parts</code>&nbsp;folder in de root van het thema.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Uitgebreide ondersteuning voor query loop blokken</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/core/2022/10/10/extending-the-query-loop-block/\">Met nieuwe filters kunnen</a>&nbsp;query blok variaties aangepaste query&#8217;s ondersteunen voor krachtigere variaties en geavanceerde filteropties voor hiërarchische berichttypen.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Filters voor al je stijlen</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/core/2022/10/10/filters-for-theme-json-data/\">Maak gebruik van filters</a>&nbsp;in de zijbalk stijlen om instellingen op alle vier de niveaus van je site te beheren: core, thema, gebruiker of blok, van minder tot meer specifiek.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Afstandsinstellingen voor een sneller en consistent ontwerp</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Bespaar tijd en vermijd het hard coderen van waarden in een thema met&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/07/introduction-of-presets-across-padding-margin-and-block-gap/\">vooraf ingestelde marge en padding waarden voor meerdere blokken</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Performance hoogtepunten</h3>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.1 loste meer dan 25 tickets op die waren bedoeld om de prestaties te verbeteren. Van de&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/10/performance-improvements-to-the-rest-api/\">REST API</a>&nbsp;tot&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/10/multisite-improvements-in-wordpress-6-1/\">multisite</a>,&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/07/improvements-to-wp_query-performance-in-6-1/\"><code>WP_Query</code></a>&nbsp;tot&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/07/improved-php-performance-for-core-blocks-registration/\">core blok registratie</a>&nbsp;en&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/06/new-cache-site-health-checks-in-wordpress-6-1/\">nieuwe sitediagnose controles</a>&nbsp;tot de toevoeging van het&nbsp;<code>async</code>&nbsp;attribuut aan afbeeldingen, er zijn prestatieverbeteringen voor elk type site. Een volledig overzicht vindt je in de&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/11/performance-field-guide-for-wordpress-6-1/\">Performance Field Guide</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Wees een van de eersten die de nieuwste verbeteringen ontvangt door de&nbsp;<a href=\"https://nl.wordpress.org/plugins/performance-lab/\">Performance Lab plug</a>&nbsp;in toe te voegen aan je WordPress testsite of sandbox.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Ondersteuning voor bewerken van inhoud voor containerblokken</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Dankzij de&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/11/content-locking-features-and-updates/\">content-only bewerken instellingen</a>&nbsp;kunnen lay-outs worden vergrendeld in containerblokken. In een blok met alleen inhoud zijn de subitems onzichtbaar voor de lijstweergave en kunnen ze volledig niet worden bewerkt. Dus je bepaalt de lay-out terwijl je schrijvers zich kunnen concentreren op de inhoud.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Combineer het met blok vergrendelingsopties voor nog meer geavanceerde controle over je blokken.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:33.33%\">\n<figure class=\"wp-block-image size-large\"><a href=\"https://youtu.be/1w9oywSa6Hw\"><img decoding=\"async\" src=\"//www.w3.org/2000/svg\'%3E%3Cg clip-path=\'url(%23a)\'%3E%3Crect width=\'269\' height=\'163\' rx=\'4\' fill=\'%23FDFF85\'/%3E%3Cpath d=\'M238.84 130.043a1 1 0 0 0-1.524.852v8.21a1 1 0 0 0 1.524.852l6.671-4.105a1 1 0 0 0 0-1.703l-6.671-4.106Z\' fill=\'%231E1E1E\'/%3E%3Crect x=\'226.25\' y=\'120.25\' width=\'29.5\' height=\'29.5\' rx=\'2.75\' stroke=\'%231E1E1E\' stroke-width=\'1.5\'/%3E%3Cpath d=\'M99.597 127.44c-6.16 0-11.36-1.16-15.6-3.48-4.24-2.32-7.68-5.4-10.32-9.24-2.56-3.84-4.4-8.16-5.52-12.96A64.74 64.74 0 0 1 66.477 87c0-9.28 1.28-17.4 3.84-24.36 2.64-6.96 6.4-12.36 11.28-16.2 4.88-3.92 10.8-5.88 17.76-5.88 5.521 0 10.241 1.08 14.161 3.24s6.96 5.04 9.12 8.64c2.24 3.6 3.6 7.52 4.08 11.76h-11.88c-.72-4.16-2.44-7.36-5.16-9.6-2.72-2.24-6.2-3.36-10.44-3.36-5.84 0-10.68 2.76-14.52 8.28-3.76 5.44-5.76 13.84-6 25.2 1.92-3.52 4.88-6.52 8.88-9 4.08-2.48 8.76-3.72 14.04-3.72 4.72 0 9.12 1.12 13.2 3.36 4.16 2.24 7.52 5.4 10.08 9.48 2.64 4 3.96 8.76 3.96 14.28 0 4.88-1.2 9.48-3.6 13.8-2.4 4.32-5.8 7.84-10.2 10.56-4.32 2.64-9.48 3.96-15.48 3.96Zm-.72-11.04c3.361 0 6.361-.72 9.001-2.16 2.64-1.44 4.72-3.4 6.24-5.88 1.52-2.56 2.28-5.44 2.28-8.64 0-5.12-1.68-9.2-5.04-12.24-3.28-3.04-7.48-4.56-12.6-4.56-3.36 0-6.4.76-9.12 2.28-2.64 1.52-4.72 3.56-6.24 6.12-1.52 2.48-2.28 5.24-2.28 8.28 0 3.28.76 6.2 2.28 8.76 1.6 2.48 3.72 4.44 6.36 5.88 2.72 1.44 5.76 2.16 9.12 2.16Zm45.925 10.32c-2.4 0-4.4-.76-6-2.28-1.52-1.6-2.28-3.48-2.28-5.64 0-2.24.76-4.12 2.28-5.64 1.6-1.6 3.6-2.4 6-2.4s4.36.8 5.88 2.4c1.52 1.52 2.28 3.4 2.28 5.64 0 2.16-.76 4.04-2.28 5.64-1.52 1.52-3.48 2.28-5.88 2.28Zm26.814-.72V56.4l-13.56 3.12v-9.36l18.6-8.16h8.16v84h-13.2Z\' fill=\'%231E1E1E\'/%3E%3C/g%3E%3Cdefs%3E%3CclipPath id=\'a\'%3E%3Crect width=\'269\' height=\'163\' rx=\'4\' fill=\'%23fff\'/%3E%3C/clipPath%3E%3C/defs%3E%3C/svg%3E%0A\" alt=\"\" /></a></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:66.66%\">\n<h3 class=\"wp-block-heading has-extra-large-font-size\">Meer leren over WordPress 6.1</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Bekijk WordPress 6.1 in actie!&nbsp;<a href=\"https://youtu.be/1w9oywSa6Hw\">Bekijk een korte overzichtsvideo</a>&nbsp;waarin enkele van de belangrijkste functies die debuteren in WordPress 6.1 worden uitgelicht.</p>\n</div>\n</div>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"wp-block-paragraph\">Ontdek&nbsp;<a href=\"https://learn.wordpress.org/\">learn.wordpress.org</a>&nbsp;voor tutorial video&#8217;s, online workshops, cursussen en lesplannen voor Meetup organisatoren, inclusief nieuwe functies in WordPress.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"wp-block-paragraph\">De laatste versie van de&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/12/wordpress-6-1-field-guide/\">WordPress field guide</a>&nbsp;bekijken. Het staat vol met gedetailleerde ontwikkelaars notities om je te helpen bouwen met WordPress.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/support/wordpress-version/version-6-1/\">Lees de WordPress 6.1 release notes</a>&nbsp;voor meer informatie over de opgenomen verbeteringen en opgeloste problemen, installatie-informatie, reacties en bronnen van ontwikkelaars, medewerkers aan de release en de lijst met bestandswijzigingen in deze release.</p>\n</div>\n</div>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:76:\"https://nl.wordpress.org/2022/11/01/wordpress-6-1-misha-is-vrijgegeven/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1227\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"WordPress 6.0 “Arturo” is vrijgegeven\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:72:\"https://nl.wordpress.org/2022/05/25/wordpress-6-0-arturo-is-vrijgegeven/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"https://nl.wordpress.org/2022/05/25/wordpress-6-0-arturo-is-vrijgegeven/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 25 May 2022 07:46:36 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"Release\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://nl.wordpress.org/?p=1211\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:363:\"Welcome to &#8220;Arturo&#8221; Verwelkom &#8220;Arturo&#8221;, oftewel WordPress 6.0, dat is geinspireerd op de met een Grammy-winnende Arturo O’Farrill. Hij staat bekend om zijn invloed op de moderne Latin jazz en heeft meer dan 15 albums uitgebracht in een periode van vijf decenia. Neem de tijd om WordPress 6.0 ter verkennen. Het is gemaakt om je [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Remkus de Vries\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:11396:\"\n<figure class=\"wp-block-image size-full\"><img decoding=\"async\" src=\"https://i2.wp.com/wordpress.org/news/files/2022/05/Main-image-News-post.png?fit=4161%2C2822&amp;ssl=1\" alt=\"WordPress 6.0 Arturo\" class=\"wp-image-12919\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Welcome to &#8220;Arturo&#8221;</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Verwelkom &#8220;Arturo&#8221;, oftewel WordPress 6.0, dat is geinspireerd op de met een Grammy-winnende  <a href=\"https://en.wikipedia.org/wiki/Arturo_O\'Farrill\">Arturo O’Farrill</a>. Hij staat bekend om zijn invloed op de moderne Latin jazz en heeft meer dan 15 albums uitgebracht in een periode van vijf decenia.</p>\n\n\n\n<span id=\"more-1211\"></span>\n\n\n\n<p class=\"wp-block-paragraph\">Neem de tijd om WordPress 6.0 ter verkennen. Het is gemaakt om je te helpen om je creatieve ambities waar te maken en om het bouwen van je site intuitiever te maken. En luister ook eens naar Arturo&#8217;s inspirerende muziek die gaat van Afro-Cubaanse jazz tot moderne latin jazz, en nog veel meer.</p>\n\n\n\n<p class=\"wp-block-paragraph\">De tweede grote release van 2022, met bijna 1000 verbeteringen en opgeloste bugs, is er. En <a href=\"https://nl.wordpress.org/wordpress-6.0-nl_NL.zip\">je kan hem nu downloaden</a>! Vandaag de dag draait meer dan 42% van de websites wereldwijd op WordPress.<sup><a href=\"https://wordpress.org/news/wp-admin/post.php?post=12879&amp;action=edit#footnote\">1</a></sup></p>\n\n\n\n<p class=\"wp-block-paragraph\"> Website-eigenaren en -beheerders zouden moeten upgraden om meteen maximaal te profiteren van de vele verbeteringen op het gebied van stabiliteit, prestaties en gebruiksvriendelijkheid. Contentmakers kunnen genieten van een reeks nieuwe mogelijkheden die zijn gericht op het verbeteren van zowel de schrijf- als de ontwerpervaring in WordPress.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">Het uitbreiden van Gutenberg naar een complete site-editorervaring in WordPress betekent dat alle problemen die de community moest oplossen ingewikkeld waren en verstrekkende gevolgen hadden. WordPress 6.0 is een voorbeeld van de toewijding van de community om deze moeilijke uitdagingen samen aan te gaan. Door de weldoordachte updates aan de schrijfervaring, het bouwen van betere blokfunctionaliteit en het toevoegen van een intuitieve nieuwe stijlswitcher ben ik echt trots op het werk dat in deze versie is gedaan om de ervaring bij het aanpassen van je site te verbeteren. </p>\n<cite>Josepha Haden Chomphosy, Executive Director</cite></blockquote>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"https://nl.wordpress.org/wordpress-6.0-nl_NL.zip\">Download WordPress 6.0</a></div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\">Wat zit er in?</h2>\n\n\n\n<figure class=\"wp-block-image size-full\"><img decoding=\"async\" src=\"https://i2.wp.com/wordpress.org/news/files/2022/05/Writing-Improvements-1.png?fit=1204%2C700&amp;ssl=1\" alt=\"Selecting multiple lines of text from two blocks\" class=\"wp-image-12887\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Verbeterde schrijfervaring</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Er zijn verbeteringen voor het schrijven in overvloed, of je nou een volledige nieuw bericht schrijft of elementen toevoegt aan een bestaande pagina. Ontdek meer manieren om het maken van je content te stroomlijnen, zoals:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Selecteer tekst in meerdere blokken en bewerk deze in één keer.</li>\n\n\n\n<li>Typ twee haakjes open&nbsp;<code>[[</code>&nbsp;om snel toegang te krijgen tot het linkmenu.</li>\n\n\n\n<li>Behoud bestaande stijlen wanneer je bepaalde blokken transformeert van de ene soort naar de andere &#8211; bijvoorbeeld van een paragraaf blok naar een code blok.</li>\n\n\n\n<li>Maak aangepaste knoppen en alle nieuwe knoppen die je maakt zullen de stijlaanpassingen automatisch behouden.</li>\n\n\n\n<li>Maak tag clouds en sociale pictogrammen nog aantrekkelijker met geüpdate instellingen en bedieningselementen, en een nieuwe omtrekstijl voor de tag cloud.</li>\n</ul>\n\n\n\n<figure class=\"wp-block-image size-full\"><img decoding=\"async\" src=\"https://i0.wp.com/wordpress.org/news/files/2022/05/Style-switcher-big.gif?fit=1204%2C700&amp;ssl=1\" alt=\"Style variations of Twenty Twenty Two theme\" class=\"wp-image-12893\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Style Switching&nbsp;</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Blokthema&#8217;s hebben nu de optie om meerdere stijlvariaties te bevatten. Dit breidt het nieuwe stijlsysteem nog verder uit en maakt het mogelijk om via shortcuts het uiterlijk van je site te veranderen, allemaal binnen één thema. Je kunt zowel de beschikbare instellingen veranderen, zoals het gewicht van het lettertype, als de stijlopties, zoals het standaard kleurenpalet. Verander het uiterlijk en de uitstraling van je site met slechts een paar klikken.</p>\n\n\n\n<hr class=\"wp-block-separator has-text-color has-vivid-red-color has-alpha-channel-opacity has-vivid-red-background-color has-background is-style-wide\" />\n\n\n\n<figure class=\"wp-block-image size-full\"><img decoding=\"async\" src=\"https://i2.wp.com/wordpress.org/news/files/2022/05/Expanded-templates.png?fit=1204%2C700&amp;ssl=1\" alt=\"Popover listing available templates\" class=\"wp-image-12889\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Meer Template opties</h3>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.0 bevat vijf nieuwe template-opties: auteur, datum, categorieën, tag en taxonomie. Deze extra templates bieden meer flexibiliteit voor makers van inhoud. Pas ze aan met de gereedschappen die je al kent of met de volgende nieuwe opties in deze release.:&nbsp;</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Uitgelichte afbeeldingen kunnen gebruikt worden in het omslagafbeeldingsblok.</li>\n\n\n\n<li>Tijdens het bewerken van een template, aan de basis of tussen blokken, toont de snelle invoegtoepassing je patronen en template-onderdelen om je te helpen sneller te werken en nieuwe lay-out-opties te ontdekken.</li>\n\n\n\n<li>Het queryblok ondersteunt filteren op meerdere auteurs, ondersteuning voor aangepaste taxonomieën, en ondersteuning voor het aanpassen van wat er wordt getoond als er geen resultaten zijn.</li>\n</ul>\n\n\n\n<figure class=\"wp-block-image size-full\"><img decoding=\"async\" src=\"https://i1.wp.com/wordpress.org/news/files/2022/05/Integrated-Patterns.png?fit=1204%2C700&amp;ssl=1\" alt=\"Browsing footer patterns in the quick inserter\" class=\"wp-image-12890\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Geïntegreerde patronen</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Patronen verschijnen nu nog vaker wanneer je ze nodig hebt, zoals in de snelle invoegfunctie of bij het maken van een nieuwe kop- of voettekst. Als je een blokthema-auteur bent, kun je zelfs <a href=\"https://make.wordpress.org/core/2022/05/02/new-features-for-working-with-patterns-and-themes-in-wordpress-6-0/\">patronen registreren uit de Pattern Directory met behulp van <code>theme.json</code></a>, zodat je prioriteit kunt geven aan specifieke patronen die het meest nuttig zijn voor de gebruikers van je thema.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Betere lijstweergave</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Nieuwe sneltoetsen stellen je in staat om meerdere blokken uit de lijstweergave te selecteren, ze in bulk te wijzigen, en ze binnen de lijst te verslepen. De lijstweergave kan gemakkelijk worden geopend en gesloten; ze is standaard samengevouwen en wordt automatisch uitgevouwen tot de huidige selectie wanneer je een blok selecteert.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Block Locking Controls</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Now you can lock your blocks. Choose to disable the option to move a block, remove a block, or both. This simplifies project handover, allowing your clients to unleash their creativity without worrying about accidentally breaking their site in the process.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Verbeterde Performance in WordPress 6.0</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Deze release bevat verschillende updates gericht op het verbeteren van de performance van WordPress. Deze verbeteringen bestrijken een reeks prestatiegebieden, waaronder het verbeteren van de pagina- en post-laad-snelheid, het verminderen van de uitvoeringstijd van verschillende querytypes, caching, navigatiemenu&#8217;s en nog veel meer. De performance team working group is een belangrijk aandachtsgebied van het kernontwikkelteam. Voor meer informatie over het werk van deze groep, volg hun werk op Making WordPress met de <a href=\"https://make.wordpress.org/core/tag/performance/\">#performance hashtag</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Verbeterde toegankelijkheid in WordPress 6.0 </h2>\n\n\n\n<p class=\"wp-block-paragraph\">Toegankelijkheid is een integraal onderdeel van de WordPress-missie om een inclusieve community te bevorderen en gebruikers van alle soorten over de hele wereld te ondersteunen. Met dit in gedachten bevat WordPress 6.0 meer dan 50 updates die specifiek gericht zijn op het verbeteren van de toegankelijkheid van het platform. Je kunt <a href=\"https://make.wordpress.org/core/2022/04/20/wordpress-6-0-accessibility-improvements/\">meer over deze updates lezen</a> alsook over de lopende toegankelijkheidsinitiatieven.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Leer meer over WordPress 6.0</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Bekijk WordPress 6.0 in actie!&nbsp;<a href=\"https://www.youtube.com/watch?v=oe452WcY7fA\">Bekijk een korte overzichtsvideo</a>&nbsp;waarin enkele van de belangrijkste functies die debuteren in WordPress 6.0 worden uitgelicht.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"Introducing WordPress 6.0\" width=\"500\" height=\"281\" src=\"https://www.youtube.com/embed/oe452WcY7fA?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\n</div></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Verken&nbsp;<a href=\"https://learn.wordpress.org/workshops/\">learn.wordpress.org/​​workshops</a>&nbsp;voor korte instructievideo&#8217;s en nog veel meer over nieuwe functies in WordPress. Of neem deel aan een live&nbsp;<a href=\"https://learn.wordpress.org/social-learning/\">interactieve online leersessie</a>&nbsp;over een specifiek WordPress-onderwerp.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Ontwikkelaars kunnen de <a href=\"https://make.wordpress.org/core/2022/05/03/wordpress-6-0-field-guide/\">WordPress 6.0 Field Guide</a> verkennen. Het staat vol met gedetailleerde ontwikkelaarsnotities die je helpen bij het bouwen en uitbreiden van WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/support/wordpress-version/version-6-0/\">Lees de WordPress 6.0 releaselog</a>&nbsp;voor meer informatie over de opgenomen verbeteringen en opgeloste problemen, installatie informatie, ontwikkelaarsnotities en bronnen, bijdragers aan de release, en de lijst van bestandswijzigingen in deze release.</p>\n\n\n\n<p class=\"wp-block-paragraph\">1&nbsp;<a href=\"https://w3techs.com/technologies/overview/content_management\">Op basis van data van W3Techs op 5 mei 2022</a>.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"https://nl.wordpress.org/2022/05/25/wordpress-6-0-arturo-is-vrijgegeven/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1211\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:47:\"WordCamp Nederland staat weer op het programma!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"https://nl.wordpress.org/2022/05/20/wordcamp-nederland-staat-weer-op-het-programma/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:91:\"https://nl.wordpress.org/2022/05/20/wordcamp-nederland-staat-weer-op-het-programma/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 20 May 2022 12:33:59 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Algemeen\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://nl.wordpress.org/?p=1191\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:344:\"WordCamp Nederland, dé Nederlandse conferentie op het gebied van WordPress, is terug van weggeweest! Op 15 en 16 september 2022 kan je in het Safari Meeting Center van Burgers&#8217; Zoo alles leren over WordPress. De laatste editie van WCNL was in 2016. In de jaren die volgden waren er wel kleinere WordCamps in diverse Nederlandse [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Taco Verdonschot\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:10079:\"\n<p class=\"wp-block-paragraph\">WordCamp Nederland, dé Nederlandse conferentie op het gebied van WordPress, is terug van weggeweest! Op <a rel=\"noreferrer noopener\" href=\"https://netherlands.wordcamp.org\" target=\"_blank\">15 en 16 september 2022 kan je in het Safari Meeting Center van Burgers&#8217; Zoo</a> alles leren over WordPress. De laatste editie van WCNL was in 2016. In de jaren die volgden waren er wel kleinere WordCamps in diverse Nederlandse steden, maar pas nu in 2022, zijn we terug met WordCamp Nederland!</p>\n\n\n\n<h2 class=\"wp-block-heading\">Wat is WordCamp?</h2>\n\n\n\n<span id=\"more-1191\"></span>\n\n\n\n<p class=\"wp-block-paragraph\"><a rel=\"noreferrer noopener\" href=\"https://wordcamp.org\" target=\"_blank\">WordCamp</a> is de naam die (internationaal) wordt gegeven aan WordPressconferenties die worden georganiseerd onder de vlag van de wereldwijde organisatie WordPress Community Support. Veel landen en steden hebben (jaarlijks) een WordCamp, omdat het een fijne manier is om de WordPresscommunity te leren kennen en samen meer te leren over de software en de toepassingen van WordPress.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Wie komt er naar een WordCamp?</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Iedereen. Nouja, dat is misschien wat overdreven. Maar iedereen die iets doet met WordPress, of er meer over wilt leren is welkom op een WordCamp. Je hebt geen certificering, lidmaatschap of basisvaardigheden nodig om deel te nemen. Je interesse is voldoende!</p>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image aligncenter size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"400\" height=\"267\" src=\"https://nl.wordpress.org/files/2022/05/29707365293_f465b285cf_w.jpg\" alt=\"\" class=\"wp-image-1193\" srcset=\"https://nl.wordpress.org/files/2022/05/29707365293_f465b285cf_w.jpg 400w, https://nl.wordpress.org/files/2022/05/29707365293_f465b285cf_w-300x200.jpg 300w\" sizes=\"auto, (max-width: 400px) 100vw, 400px\" /><figcaption class=\"wp-element-caption\">Foto van de foyer door Henk-Jan Winkeldermaat (<a href=\"http://punkmedia.nl/\">punkmedia.nl</a>)</figcaption></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"wp-block-paragraph\">Onder de deelnemers vind je daarom alle soorten mensen. Van de hobbyblogger die net is begonnen tot de ervaren developer die al tientallen plugins heeft gebouwd. En van marketing managers tot de eigenaren van webontwikkelbureau&#8217;s. Leeftijd? Iedereen is welkom! Achtergrond? Maakt niet uit. De WordPress community is heel inclusief en er is voor iedereen plek, mits je je aan de gedragsregels houdt natuurlijk.</p>\n</div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\">Waarom zou ik naar een WordCamp gaan?</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Om te leren. Om te netwerken. Voor de gezelligheid. Om vrienden en bekenden te ontmoeten. Om zakelijke samenwerkingen aan te gaan. Om contact te hebben met klanten. Om je expertise te delen. Hoe meer mensen je het vraagt, des te meer verschillende antwoorden zal je krijgen. Er is namelijk heel veel te halen op een WordCamp.</p>\n\n\n\n<figure class=\"wp-block-image aligncenter size-full\"><a href=\"https://nl.wordpress.org/files/2022/05/30252813321_2c5576e09a_w.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"400\" height=\"267\" src=\"https://nl.wordpress.org/files/2022/05/30252813321_2c5576e09a_w.jpg\" alt=\"\" class=\"wp-image-1194\" srcset=\"https://nl.wordpress.org/files/2022/05/30252813321_2c5576e09a_w.jpg 400w, https://nl.wordpress.org/files/2022/05/30252813321_2c5576e09a_w-300x200.jpg 300w\" sizes=\"auto, (max-width: 400px) 100vw, 400px\" /></a><figcaption class=\"wp-element-caption\">Presentatie van Jaime Martinez tijdens WCNL 2016, foto door Henk-Jan Winkeldermaat (<a href=\"http://punkmedia.nl/\">punkmedia.nl</a>)</figcaption></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Natuurlijk draait WordCamp grotendeels om de prachtige presentaties die worden gegeven. Sprekers besteden flink tijd aan het voorbereiden en geven van hun presentaties. Sponsoren (veelal WordPress-gerelateerde bedrijven) laten het beste van zichzelf zien en in de wandelgangen (ook bekend als &#8216;hallway track&#8217;) vinden bijzondere ontmoetingen plaats. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Het aantal beschikbare plekken is trouwens gelimiteerd, dus zorg dat je op tijd bent met het kopen van je kaartje!</p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button aligncenter\"><a class=\"wp-block-button__link wp-element-button\" href=\"https://netherlands.wordcamp.org/2022/tickets/\">Koop je tickets voor WCNL!</a></div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\">Kan ik mijn kennis ook delen?</h2>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image aligncenter size-full\"><a href=\"https://nl.wordpress.org/files/2022/05/29707115283_8fdc92f910_w.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"400\" height=\"267\" src=\"https://nl.wordpress.org/files/2022/05/29707115283_8fdc92f910_w.jpg\" alt=\"\" class=\"wp-image-1195\" srcset=\"https://nl.wordpress.org/files/2022/05/29707115283_8fdc92f910_w.jpg 400w, https://nl.wordpress.org/files/2022/05/29707115283_8fdc92f910_w-300x200.jpg 300w\" sizes=\"auto, (max-width: 400px) 100vw, 400px\" /></a><figcaption class=\"wp-element-caption\">Petya Raykovska presenteert tijdens WCNL 2016, foto door Henk-Jan Winkeldermaat (<a href=\"http://punkmedia.nl/\">punkmedia.nl</a>)</figcaption></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"wp-block-paragraph\">Natuurlijk kan dat! WordCamp Nederland heeft een oproep geplaatst om te komen spreken. Je hoeft daarvoor geen ervaren spreker te zijn, al raden we je wel aan om al eens eerder voor een groep te hebben gepraat. Dat kan bijvoorbeeld <a rel=\"noreferrer noopener\" href=\"https://nl.wordpress.org/community/meetups/\" target=\"_blank\">op een meetup</a>. </p>\n\n\n\n<p class=\"wp-block-paragraph\">WCNL biedt overigens aan om je in contact te brengen met een ervaring spreker om je te coachen, dus dat helpt je sowieso!</p>\n</div>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\">Weet je al waar je over wilt gaan vertellen op WCNL? <a href=\"https://netherlands.wordcamp.org/2022/calls/meld-je-aan-als-spreker/\" target=\"_blank\" rel=\"noreferrer noopener\">Meld je dan vandaag nog aan</a>, je hebt nog maar tot 1 juni!</p>\n\n\n\n<h2 class=\"wp-block-heading\">Ik vind dit een beetje spannend&#8230;</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Dat snappen we! Vooral na 2 jaar weinig mensen zien is een evenement van bijna 500 deelnemers gigantisch, vooral als je niemand kent. Gelukkig hebben we daar een oplossing voor!</p>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"wp-block-paragraph\">WordCamps worden volledig georganiseerd door vrijwilligers. Dat betekent dat er op de conferentiedagen zelf ook handjes nodig zijn om belangrijke taken uit te voeren. Daarom kan je je <a rel=\"noreferrer noopener\" href=\"https://netherlands.wordcamp.org/2022/calls/meld-je-aan-als-vrijwilliger/\" target=\"_blank\">aanmelden op onze site</a> als vrijwilliger. Door samen te werken leer je elkaar kennen, en samen leer je nog veel meer mensen kennen! </p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><a href=\"https://nl.wordpress.org/files/2022/05/30061334030_c6d31f0760_w.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"400\" height=\"267\" src=\"https://nl.wordpress.org/files/2022/05/30061334030_c6d31f0760_w.jpg\" alt=\"\" class=\"wp-image-1196\" srcset=\"https://nl.wordpress.org/files/2022/05/30061334030_c6d31f0760_w.jpg 400w, https://nl.wordpress.org/files/2022/05/30061334030_c6d31f0760_w-300x200.jpg 300w\" sizes=\"auto, (max-width: 400px) 100vw, 400px\" /></a><figcaption class=\"wp-element-caption\">De vrijwilligers staan klaar om al je problemen op te lossen, foto door Henk-Jan Winkeldermaat (<a href=\"http://punkmedia.nl/\">punkmedia.nl</a>)</figcaption></figure>\n</div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\">Overtuigd?</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Ben je overtuigd dat je ook naar WCNL moet komen? Mooi! Hieronder nog een keer de belangrijkste linkjes:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://netherlands.wordcamp.org/2022/\">WordCamp Nederland</a></li>\n\n\n\n<li><a href=\"https://netherlands.wordcamp.org/2022/calls/meld-je-aan-als-vrijwilliger/\">WordCamp Nederland zoekt vrijwilligers</a></li>\n\n\n\n<li><a href=\"https://netherlands.wordcamp.org/2022/calls/meld-je-aan-als-spreker/\">WordCamp Nederland zoekt sprekers</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Vragen?</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Stel ze hieronder in de comments, of check de pagina van <a href=\"https://netherlands.wordcamp.org\">WordCamp Nederland</a>.<br></p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Tot ziens op WordCamp Nederland?</em></p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://nl.wordpress.org/files/2022/05/30271992231_c4bd654bdb_c.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"582\" src=\"https://nl.wordpress.org/files/2022/05/30271992231_c4bd654bdb_c.jpg\" alt=\"\" class=\"wp-image-1200\" srcset=\"https://nl.wordpress.org/files/2022/05/30271992231_c4bd654bdb_c.jpg 800w, https://nl.wordpress.org/files/2022/05/30271992231_c4bd654bdb_c-300x218.jpg 300w, https://nl.wordpress.org/files/2022/05/30271992231_c4bd654bdb_c-768x559.jpg 768w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /></a><figcaption class=\"wp-element-caption\">Wendie en Wendy zien je ook graag op WCNL, foto door Henk-Jan Winkeldermaat (<a href=\"http://punkmedia.nl/\">punkmedia.nl</a>)</figcaption></figure>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"https://nl.wordpress.org/2022/05/20/wordcamp-nederland-staat-weer-op-het-programma/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1191\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:35:\"https://nl.wordpress.org/news/feed/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:44:\"http://purl.org/rss/1.0/modules/syndication/\";a:2:{s:12:\"updatePeriod\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"\n	hourly	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:15:\"updateFrequency\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"\n	1	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:4:\"site\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"13096073\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";O:48:\"WpOrg\\Requests\\Utility\\CaseInsensitiveDictionary\":1:{s:7:\"\0*\0data\";a:11:{s:6:\"server\";s:5:\"ngin