(3254,'_transient_upgrade_gravity_form_styler','O:8:\"stdClass\":2:{s:15:\"current_version\";s:5:\"1.0.3\";s:15:\"update_metadata\";s:3496:\"O:8:\"stdClass\":12:{s:4:\"slug\";s:34:\"divi-extended-gravity-forms-styler\";s:4:\"name\";s:29:\"Gravity Forms Styler for Divi\";s:7:\"banners\";a:2:{s:3:\"low\";s:95:\"https://diviextended.com/wp-content/uploads/2022/08/gravity-forms-styler-for-divi-772x250-1.jpg\";s:4:\"high\";s:96:\"https://diviextended.com/wp-content/uploads/2022/08/gravity-forms-styler-for-divi-1544x500-1.jpg\";}s:6:\"author\";s:39:\"<a href=\"https://elicus.com\">Elicus</a>\";s:8:\"homepage\";s:63:\"https://diviextended.com/product/gravity-forms-styler-for-divi/\";s:12:\"contributors\";a:4:{s:6:\"elicus\";a:3:{s:12:\"display_name\";s:6:\"Elicus\";s:7:\"profile\";s:38:\"https://profiles.wordpress.org/elicus/\";s:6:\"avatar\";s:85:\"https://secure.gravatar.com/avatar/e1286d3a13dda6ec89bc2b64ac1d990e?s=150&d=retro&r=g\";}s:11:\"poonamsaini\";a:3:{s:12:\"display_name\";s:12:\"Poonam Saini\";s:7:\"profile\";s:43:\"https://profiles.wordpress.org/poonamsaini/\";s:6:\"avatar\";s:81:\"https://secure.gravatar.com/avatar/25e348ec82eee3f8e4e9426dba88d847?s=36&d=mm&r=g\";}s:14:\"ankurkhurana18\";a:3:{s:12:\"display_name\";s:13:\"Ankur Khurana\";s:7:\"profile\";s:44:\"https://profiles.wordpress.org/ankurkhurana/\";s:6:\"avatar\";s:82:\"https://secure.gravatar.com/avatar/08c0090aa4da3acbc048e1260c192455?s=100&d=mm&r=g\";}s:11:\"themohdarif\";a:3:{s:12:\"display_name\";s:9:\"Mohd Arif\";s:7:\"profile\";s:42:\"http://profiles.wordpress.org/themohdarif/\";s:6:\"avatar\";s:81:\"https://secure.gravatar.com/avatar/b46ef8f72b901c074e08d43bd325bb4b?s=36&d=mm&r=g\";}}s:7:\"version\";s:5:\"1.0.3\";s:12:\"download_url\";s:70:\"http://cdn.elicus.com/divi-extended-gravity-forms-styler/downloads.php\";s:8:\"requires\";s:5:\"6.0.0\";s:6:\"tested\";s:3:\"6.3\";s:12:\"last_updated\";s:10:\"2024-08-16\";s:8:\"sections\";a:4:{s:11:\"description\";s:116:\"Gravity Forms Styler for Divi is an all-in-one Divi plugin to add and style your Gravity Forms in Divi effortlessly.\";s:12:\"installation\";s:550:\"<p>Upload divi-extended-gravity-forms-styler-x.x on your website from the WordPress Dashboard and activate it.</p>\n        					<p>Gravity Forms Styler module will be added on page builder module list.</p>\n							<p>Go to a page, edit it using Divi builder and add the module. Once the module is added to the page, use the module settings to select content and format the module. For detailed setup and customization process, please visit the <a href=\"https://diviextended.com/documentation/gravity-forms-styler-for-divi/\">documentation</a> page.</p>\";s:9:\"changelog\";s:866:\"<h4>1.0.3</h4>\n							<p><em>Release date: 16th August 2024</em></p>\n							<ul>\n								<li>Added: Control for Submit button alignment.</li>\n								<li>FIXED: PHP 8 depreciation error.</li>								\n							</ul>\n							<h4>1.0.2</h4>\n							<p><em>Release date: 25th September 2023</em></p>\n							<ul>\n								<li>FIXED: Random string coming on the page where gravity form styler module is used.</li>\n							</ul>\n							<h4>1.0.1</h4>\n							<p><em>Release date: 21st September 2023</em></p>\n							<ul>\n								<li>Added: Padding and Background Color control for Error and Success message.</li>\n								<li>Fixed: Form was not visible on visual builder when any of the form field has active conditional logic.</li>\n							</ul>\n							<h4>1.0.1</h4>\n							<p><em>Release date: 05th August 2022</em></p>\n							<ul>\n								<li>Initial release.</li>\n							</ul>\";s:3:\"FAQ\";s:174:\"<h4>What is Gravity Form Styler for Divi?</h4>\n							<p>Gravity Forms Styler for Divi is a plugin that adds a new module in Divi theme builder for styling Gravity Forms.</p>\";}}\";}','off'),
